// ─────────────────────────────────────────────────────────────────────────────
// Expanded DTOT question bank.
//
// These supplement the base set in seed.ts so the bank exceeds the official
// full-length DTOT section counts (Job Knowledge 60, Situational Judgment 28,
// English Expression 65), leaving a buffer so repeat full exams aren't identical.
//
// Job Knowledge is written at roughly CompTIA A+/Network+/Security+ difficulty,
// applied to a U.S. embassy IT environment (per public descriptions of the DTO
// role and first-hand accounts of the DTOT).
// ─────────────────────────────────────────────────────────────────────────────

export const JOB_KNOWLEDGE_EXTRA = [
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"EASY","prompt":"An embassy workstation is configured to obtain its IP address automatically. Which protocol assigns the workstation an IP address, subnet mask, default gateway, and DNS server when it connects to the network?","options":[{"id":"A","text":"DNS"},{"id":"B","text":"DHCP"},{"id":"C","text":"SNMP"},{"id":"D","text":"NTP"}],"correctId":"B","rationale":"DHCP (Dynamic Host Configuration Protocol) automatically leases IP addresses and distributes network configuration such as subnet mask, default gateway, and DNS server addresses to clients. DNS resolves names to addresses, SNMP manages network devices, and NTP synchronizes clocks.","optionNotes":{"A":"DNS resolves hostnames to IP addresses; it does not assign addressing.","C":"SNMP monitors and manages network devices, not address assignment.","D":"NTP synchronizes system time, not IP configuration."},"reference":"IT & Telecommunications › DHCP"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"An embassy subnet is 192.168.20.0/26. How many usable host addresses does this subnet provide?","options":[{"id":"A","text":"30"},{"id":"B","text":"62"},{"id":"C","text":"64"},{"id":"D","text":"126"}],"correctId":"B","rationale":"A /26 leaves 6 host bits (32 - 26 = 6), giving 2^6 = 64 addresses. Subtracting the network and broadcast addresses leaves 62 usable hosts. A /27 would give 30, and a /25 would give 126.","optionNotes":{"A":"30 usable hosts corresponds to a /27.","C":"64 is the total address count, before subtracting network and broadcast addresses.","D":"126 usable hosts corresponds to a /25."},"reference":"IT & Telecommunications › Subnetting"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"An embassy wants to separate unclassified staff traffic from guest Wi-Fi traffic on the same physical switches without running additional cabling. Which technology best accomplishes this?","options":[{"id":"A","text":"Configuring VLANs and assigning ports/SSIDs to separate VLAN IDs"},{"id":"B","text":"Enabling Spanning Tree Protocol on all switch ports"},{"id":"C","text":"Increasing the DHCP lease time on the guest network"},{"id":"D","text":"Installing a second default gateway on each workstation"}],"correctId":"A","rationale":"VLANs segment a single physical switch infrastructure into separate broadcast domains, isolating staff and guest traffic logically without new cabling. STP prevents switching loops but does not segment traffic, DHCP lease time is unrelated to isolation, and adding a second gateway does not separate networks.","optionNotes":{"B":"STP prevents loops; it does not isolate traffic into separate networks.","C":"Lease time controls address renewal, not network segmentation.","D":"Multiple gateways do not create logical isolation between users."},"reference":"IT & Telecommunications › VLANs"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"A user reports they can reach internal servers by IP address but cannot reach any internal or external sites by name. Which service is the most likely cause?","options":[{"id":"A","text":"DHCP"},{"id":"B","text":"DNS"},{"id":"C","text":"NAT"},{"id":"D","text":"ARP"}],"correctId":"B","rationale":"Connectivity by IP but failure by name is the classic symptom of a DNS resolution problem. DHCP would typically prevent IP connectivity entirely, NAT handles address translation for outbound traffic, and ARP maps IP to MAC within the local segment.","optionNotes":{"A":"A DHCP failure usually leaves the host without working IP connectivity at all.","C":"NAT issues affect outbound translation, not name resolution generally.","D":"ARP resolves IP to MAC locally and would not selectively break name lookups."},"reference":"IT & Telecommunications › DNS"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"HARD","prompt":"A teleworking embassy employee uses a VPN configured for split tunneling. What is the security implication of this configuration?","options":[{"id":"A","text":"All traffic, including general web browsing, is forced through the embassy gateway for inspection"},{"id":"B","text":"Only traffic destined for embassy resources goes through the encrypted tunnel; other traffic exits directly to the internet, bypassing embassy security controls"},{"id":"C","text":"The VPN encrypts traffic twice, doubling the protection on all sessions"},{"id":"D","text":"The VPN disables DNS resolution for non-embassy domains"}],"correctId":"B","rationale":"Split tunneling sends only corporate-bound traffic through the VPN while other traffic goes directly to the internet, which improves performance but bypasses centralized security inspection and filtering. Full tunneling (not split) forces all traffic through the gateway. Split tunneling does not double-encrypt or disable DNS.","optionNotes":{"A":"That describes full tunneling, the opposite of split tunneling.","C":"Split tunneling does not perform double encryption.","D":"DNS for non-embassy domains still functions; it simply may resolve via the local connection."},"reference":"IT & Telecommunications › VPN"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"HARD","prompt":"Multiple users on one floor of the embassy intermittently lose network connectivity, and the access switch logs show ports rapidly transitioning and a MAC address flapping between two ports. What is the most likely root cause?","options":[{"id":"A","text":"A switching loop caused by a redundant link with Spanning Tree Protocol disabled or misconfigured"},{"id":"B","text":"The DHCP scope has been exhausted"},{"id":"C","text":"The DNS server is returning stale records"},{"id":"D","text":"The default gateway has an incorrect subnet mask"}],"correctId":"A","rationale":"MAC address flapping between ports plus rapid port transitions are hallmark symptoms of a Layer 2 switching loop, normally prevented by STP. DHCP exhaustion would prevent address assignment but not cause MAC flapping, and DNS or gateway misconfiguration are Layer 3 issues that would not produce MAC flapping in switch logs.","optionNotes":{"B":"Scope exhaustion blocks new leases but does not cause MAC flapping.","C":"Stale DNS records affect name resolution, not switch-level MAC behavior.","D":"A wrong mask is a Layer 3 reachability issue, not a cause of MAC flapping."},"reference":"IT & Telecommunications › Routing/switching"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"EASY","prompt":"Which command-line utility would an embassy technician most commonly use to test basic IP reachability to a remote host?","options":[{"id":"A","text":"ping"},{"id":"B","text":"chkdsk"},{"id":"C","text":"ipconfig /release"},{"id":"D","text":"format"}],"correctId":"A","rationale":"Ping sends ICMP echo requests to verify whether a remote host is reachable and to measure round-trip time. Chkdsk checks disk integrity, ipconfig /release drops the current DHCP lease, and format erases a drive.","optionNotes":{"B":"chkdsk verifies disk file system integrity, not network reachability.","C":"ipconfig /release removes the DHCP lease rather than testing connectivity.","D":"format erases and prepares a storage volume."},"reference":"IT & Telecommunications › Troubleshooting"},
{"section":"JOB_KNOWLEDGE","topic":"IT & Telecommunications","difficulty":"MEDIUM","prompt":"Which TCP/IP transport-layer protocol provides connection-oriented, reliable delivery with acknowledgments and retransmission?","options":[{"id":"A","text":"UDP"},{"id":"B","text":"ICMP"},{"id":"C","text":"TCP"},{"id":"D","text":"IP"}],"correctId":"C","rationale":"TCP is connection-oriented and provides reliability through sequencing, acknowledgments, and retransmission of lost segments. UDP is connectionless and best-effort, ICMP is used for diagnostics and error messaging, and IP is the connectionless network-layer addressing/routing protocol.","optionNotes":{"A":"UDP is connectionless and does not guarantee delivery.","B":"ICMP handles control and error messages, not reliable data transport.","D":"IP provides addressing and routing without reliability guarantees."},"reference":"IT & Telecommunications › TCP/IP"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"EASY","prompt":"An embassy subscribes to a web-based email and productivity suite where the vendor manages everything and users simply log in through a browser. Which cloud service model is this?","options":[{"id":"A","text":"IaaS"},{"id":"B","text":"PaaS"},{"id":"C","text":"SaaS"},{"id":"D","text":"On-premises"}],"correctId":"C","rationale":"Software as a Service delivers fully managed applications to end users over the internet, with the provider handling infrastructure, platform, and the application itself. IaaS provides raw compute/storage/network, PaaS provides a development/runtime platform, and on-premises means the organization runs everything itself.","optionNotes":{"A":"IaaS provides virtualized infrastructure, leaving OS and apps to the customer.","B":"PaaS provides a platform for building apps, not a finished application.","D":"On-premises means the organization hosts and manages it locally."},"reference":"Cloud Computing › Service models"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"Under the cloud shared responsibility model for an IaaS deployment, which task is typically the customer's responsibility rather than the cloud provider's?","options":[{"id":"A","text":"Securing the physical data center facilities"},{"id":"B","text":"Maintaining the underlying hypervisor host hardware"},{"id":"C","text":"Patching the guest operating system on the customer's virtual machines"},{"id":"D","text":"Replacing failed physical storage drives"}],"correctId":"C","rationale":"In IaaS, the provider secures the physical facilities, host hardware, and hypervisor, while the customer is responsible for the guest OS, applications, and data, including patching the guest operating system. Physical security, host hardware, and drive replacement are all provider responsibilities.","optionNotes":{"A":"Physical facility security is always the provider's responsibility.","B":"The provider maintains the hypervisor and host hardware in IaaS.","D":"Replacing physical drives is part of the provider-managed infrastructure."},"reference":"Cloud Computing › Shared responsibility"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"Which characteristic best describes cloud elasticity?","options":[{"id":"A","text":"Data is replicated to multiple geographic regions for durability"},{"id":"B","text":"Resources automatically scale up or down to match changing demand"},{"id":"C","text":"Multiple tenants share the same physical hardware"},{"id":"D","text":"Workloads are isolated inside separate virtual machines"}],"correctId":"B","rationale":"Elasticity is the ability to automatically provision and de-provision resources to match workload demand in near real time, often paired with pay-as-you-go billing. Geographic replication describes durability/redundancy, shared hardware describes multi-tenancy, and VM isolation describes virtualization.","optionNotes":{"A":"That describes geo-redundancy/durability, not elasticity.","C":"That describes multi-tenancy.","D":"That describes virtualization-based isolation."},"reference":"Cloud Computing › Elasticity"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"What distinguishes a container from a traditional virtual machine?","options":[{"id":"A","text":"Containers each include a full guest operating system, while VMs share the host kernel"},{"id":"B","text":"Containers share the host operating system kernel and package only the application and its dependencies, while VMs each run a full guest OS"},{"id":"C","text":"Containers can only run on bare-metal hardware, while VMs require a hypervisor"},{"id":"D","text":"Containers provide stronger hardware-level isolation than virtual machines"}],"correctId":"B","rationale":"Containers virtualize at the OS level, sharing the host kernel and bundling just the app and dependencies, making them lightweight and fast to start. VMs each include a full guest OS on top of a hypervisor. VMs, not containers, generally provide stronger hardware-level isolation.","optionNotes":{"A":"This reverses the definitions; VMs include a full guest OS, not containers.","C":"Containers commonly run on top of a host OS, not exclusively bare metal.","D":"VMs typically offer stronger isolation than containers."},"reference":"Cloud Computing › Containers"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"HARD","prompt":"A U.S. government agency must procure a cloud service that has been formally assessed and authorized to handle federal data. Which program provides this standardized security authorization for cloud products used by federal agencies?","options":[{"id":"A","text":"FedRAMP"},{"id":"B","text":"HIPAA"},{"id":"C","text":"PCI DSS"},{"id":"D","text":"COBIT"}],"correctId":"A","rationale":"FedRAMP (Federal Risk and Authorization Management Program) standardizes security assessment, authorization, and continuous monitoring for cloud products and services used by U.S. federal agencies. HIPAA covers healthcare data privacy, PCI DSS covers payment card data, and COBIT is an IT governance framework.","optionNotes":{"B":"HIPAA governs protected health information, not federal cloud authorization.","C":"PCI DSS applies to payment card processing environments.","D":"COBIT is a governance and management framework, not a cloud authorization program."},"reference":"Cloud Computing › FedRAMP/gov cloud"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"HARD","prompt":"An embassy's disaster recovery plan specifies an RTO of 4 hours and an RPO of 15 minutes. What does the RPO value specify?","options":[{"id":"A","text":"The maximum acceptable time to restore service after an outage"},{"id":"B","text":"The maximum acceptable amount of data loss measured as a point in time before the outage"},{"id":"C","text":"The total uptime guaranteed by the cloud provider's SLA"},{"id":"D","text":"The time required to fail back to the primary site"}],"correctId":"B","rationale":"Recovery Point Objective (RPO) defines the maximum tolerable data loss, expressed as how far back in time recovery must reach, so a 15-minute RPO means backups/replication must be no more than 15 minutes old. Recovery Time Objective (RTO) is the maximum time to restore service, which is the 4-hour value.","optionNotes":{"A":"That defines RTO, not RPO.","C":"SLA uptime guarantees are a separate metric from RPO.","D":"Failback time is an operational detail, not the definition of RPO."},"reference":"Cloud Computing › Backup/DR"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"EASY","prompt":"An embassy keeps highly sensitive systems on infrastructure dedicated solely to its own organization while using a public provider for routine, non-sensitive workloads. Which deployment model does this combination represent?","options":[{"id":"A","text":"Public cloud only"},{"id":"B","text":"Private cloud only"},{"id":"C","text":"Hybrid cloud"},{"id":"D","text":"Community cloud"}],"correctId":"C","rationale":"A hybrid cloud combines private (dedicated) and public cloud environments, allowing sensitive workloads to stay private while leveraging public cloud for other needs. Public-only or private-only would use a single model, and a community cloud is shared among several organizations with common requirements.","optionNotes":{"A":"Public-only would not include the dedicated private infrastructure.","B":"Private-only would exclude the public provider usage.","D":"A community cloud is shared by multiple organizations with shared concerns, not a private/public mix."},"reference":"Cloud Computing › Deployment models"},
{"section":"JOB_KNOWLEDGE","topic":"Cloud Computing","difficulty":"MEDIUM","prompt":"An embassy development team wants to deploy applications without managing servers, operating systems, or runtime patching, but still wants to write and control their own application code. Which service model best fits this need?","options":[{"id":"A","text":"IaaS"},{"id":"B","text":"PaaS"},{"id":"C","text":"SaaS"},{"id":"D","text":"DRaaS"}],"correctId":"B","rationale":"Platform as a Service provides a managed runtime, middleware, and OS so developers can deploy their own code without managing the underlying infrastructure or patching the platform. IaaS would still require the team to manage the OS, SaaS delivers finished applications with no custom code control, and DRaaS is disaster-recovery as a service.","optionNotes":{"A":"IaaS leaves OS management and patching to the customer.","C":"SaaS delivers ready-made applications, not a platform for custom code.","D":"DRaaS provides disaster recovery, not an application development platform."},"reference":"Cloud Computing › Service models"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"EASY","prompt":"Which three core principles make up the CIA triad in information security?","options":[{"id":"A","text":"Confidentiality, Integrity, Availability"},{"id":"B","text":"Control, Identity, Authorization"},{"id":"C","text":"Confidentiality, Identification, Authentication"},{"id":"D","text":"Compliance, Integrity, Auditing"}],"correctId":"A","rationale":"The CIA triad stands for Confidentiality (limiting access to authorized parties), Integrity (ensuring data is accurate and unaltered), and Availability (ensuring systems and data are accessible when needed). The other options mix in unrelated terms that are not the standard triad.","optionNotes":{"B":"These are not the components of the CIA triad.","C":"Identification and authentication are access controls, not the triad components.","D":"Compliance and auditing are governance activities, not the triad."},"reference":"Cybersecurity › CIA triad"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"EASY","prompt":"An embassy requires staff to enter a password and then approve a push notification on a government-issued phone before accessing email. Which security control does this represent?","options":[{"id":"A","text":"Single sign-on"},{"id":"B","text":"Multi-factor authentication"},{"id":"C","text":"Role-based access control"},{"id":"D","text":"Full-disk encryption"}],"correctId":"B","rationale":"Multi-factor authentication combines two or more different factor types, here something you know (password) and something you have (the phone approving the push), to verify identity. Single sign-on streamlines logins across systems, RBAC governs permissions by role, and full-disk encryption protects data at rest.","optionNotes":{"A":"SSO allows one login across services; it is not inherently multi-factor.","C":"RBAC assigns permissions by role, not identity verification factors.","D":"Full-disk encryption protects stored data, not login authentication."},"reference":"Cybersecurity › MFA"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"What is the primary advantage of asymmetric encryption over symmetric encryption?","options":[{"id":"A","text":"It is significantly faster for encrypting large volumes of data"},{"id":"B","text":"It uses a public/private key pair so parties can exchange data securely without first sharing a secret key"},{"id":"C","text":"It uses a single shared key, simplifying key management"},{"id":"D","text":"It does not rely on any mathematical algorithm"}],"correctId":"B","rationale":"Asymmetric encryption uses a mathematically related public/private key pair, solving the key-distribution problem by allowing secure communication without pre-sharing a secret. Symmetric encryption is actually faster and uses a single shared key, which is why hybrid systems use asymmetric methods to exchange a symmetric session key.","optionNotes":{"A":"Symmetric encryption is faster; asymmetric is slower and used for key exchange/signatures.","C":"Using a single shared key describes symmetric encryption.","D":"Both encryption types rely on mathematical algorithms."},"reference":"Cybersecurity › Encryption symmetric/asymmetric"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"In a public key infrastructure (PKI), what is the primary role of a Certificate Authority (CA)?","options":[{"id":"A","text":"To encrypt all network traffic between two hosts"},{"id":"B","text":"To issue and digitally sign certificates that bind a public key to a verified identity"},{"id":"C","text":"To store users' private keys on a central server"},{"id":"D","text":"To scan certificates for malware before installation"}],"correctId":"B","rationale":"A Certificate Authority validates an entity's identity and issues a digitally signed certificate binding that identity to its public key, establishing trust in PKI. CAs do not encrypt all traffic, do not centrally store users' private keys (which must stay private to the owner), and do not scan certificates for malware.","optionNotes":{"A":"Traffic encryption is performed by protocols like TLS, not the CA itself.","C":"Private keys are kept by their owners, not stored by the CA.","D":"Malware scanning is not a CA function."},"reference":"Cybersecurity › PKI/certificates"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"An embassy employee receives an urgent email appearing to be from the Ambassador, asking them to immediately purchase gift cards and send the codes, with pressure to act fast and not tell anyone. This is an example of which type of attack?","options":[{"id":"A","text":"SQL injection"},{"id":"B","text":"Social engineering (phishing/business email compromise)"},{"id":"C","text":"Denial-of-service attack"},{"id":"D","text":"Man-in-the-middle attack"}],"correctId":"B","rationale":"This is social engineering, specifically a phishing/business email compromise attack that impersonates an authority figure and uses urgency and secrecy to manipulate the victim. SQL injection targets databases, denial-of-service disrupts availability, and a man-in-the-middle attack intercepts communications rather than relying on human manipulation.","optionNotes":{"A":"SQL injection exploits database input handling, not human psychology.","C":"A DoS attack floods a service to disrupt availability.","D":"A man-in-the-middle intercepts traffic between parties rather than directly tricking a user via email."},"reference":"Cybersecurity › Social engineering"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"MEDIUM","prompt":"What is the key functional difference between an IDS and an IPS?","options":[{"id":"A","text":"An IDS only detects and alerts on suspicious activity, while an IPS can actively block or drop malicious traffic"},{"id":"B","text":"An IDS blocks traffic inline, while an IPS only logs events"},{"id":"C","text":"An IDS encrypts traffic, while an IPS decrypts it"},{"id":"D","text":"An IDS operates only at Layer 1, while an IPS operates only at Layer 7"}],"correctId":"A","rationale":"An Intrusion Detection System monitors and alerts on suspicious activity but does not block it, whereas an Intrusion Prevention System sits inline and can actively block or drop malicious traffic. Neither system encrypts/decrypts traffic, and both inspect traffic across multiple layers, not a single fixed layer.","optionNotes":{"B":"This reverses the roles; the IPS blocks inline and the IDS logs/alerts.","C":"Encryption and decryption are not the functions of IDS/IPS.","D":"Both inspect traffic at multiple layers, not a single restricted layer."},"reference":"Cybersecurity › IDS/IPS"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"Which statement best captures the core assumption of a Zero Trust security model?","options":[{"id":"A","text":"Devices inside the network perimeter are inherently trusted and need no further verification"},{"id":"B","text":"No user or device is trusted by default; every access request must be continuously authenticated, authorized, and validated regardless of location"},{"id":"C","text":"A strong perimeter firewall is sufficient to protect all internal resources"},{"id":"D","text":"Trust is granted permanently once a user completes the initial login"}],"correctId":"B","rationale":"Zero Trust operates on 'never trust, always verify,' assuming no implicit trust based on network location and requiring continuous authentication, authorization, and validation for every access request. The other options describe the traditional perimeter-based model that Zero Trust was designed to replace.","optionNotes":{"A":"Implicit internal trust is the perimeter model Zero Trust rejects.","C":"Zero Trust assumes the perimeter can be breached, so a firewall alone is insufficient.","D":"Zero Trust requires continuous, not one-time, verification."},"reference":"Cybersecurity › Zero trust"},
{"section":"JOB_KNOWLEDGE","topic":"Cybersecurity","difficulty":"HARD","prompt":"During incident response, an embassy SOC has confirmed an active malware infection spreading across several workstations. According to the standard incident response lifecycle (e.g., NIST), which phase immediately focuses on limiting the spread and isolating affected systems before removing the threat?","options":[{"id":"A","text":"Preparation"},{"id":"B","text":"Containment"},{"id":"C","text":"Eradication"},{"id":"D","text":"Lessons learned"}],"correctId":"B","rationale":"Containment is the phase that limits the damage and prevents further spread, for example by isolating affected hosts, before eradication removes the threat and recovery restores systems. Preparation occurs before an incident, eradication follows containment, and lessons learned is the final post-incident review phase.","optionNotes":{"A":"Preparation happens before any incident occurs.","C":"Eradication removes the threat but comes after containment limits spread.","D":"Lessons learned is the final review phase after recovery."},"reference":"Cybersecurity › Incident response"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"EASY","prompt":"An embassy regional security officer needs reliable voice communication over hundreds of miles to a remote consulate without relying on satellites or local infrastructure. Which band is traditionally used for this long-haul, beyond-line-of-sight skywave communication?","options":[{"id":"A","text":"HF (3-30 MHz)"},{"id":"B","text":"VHF (30-300 MHz)"},{"id":"C","text":"UHF (300 MHz-3 GHz)"},{"id":"D","text":"SHF (3-30 GHz)"}],"correctId":"A","rationale":"HF signals refract off the ionosphere (skywave propagation), allowing beyond-line-of-sight communication over hundreds to thousands of miles, which is why HF remains a staple for diplomatic and emergency long-haul radio. VHF/UHF/SHF are predominantly line-of-sight and do not reliably reflect off the ionosphere.","optionNotes":{"B":"VHF is primarily line-of-sight, suited to local/regional ranges, not transcontinental skywave.","C":"UHF is line-of-sight and even more limited in range than VHF.","D":"SHF is microwave line-of-sight (e.g., satellite uplinks), not ionospheric skywave."},"reference":"Radio Systems › Propagation"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"EASY","prompt":"A repeater at an embassy compound extends the range of handheld radios by receiving on one frequency and simultaneously retransmitting on another. The fixed difference between these two frequencies is known as the:","options":[{"id":"A","text":"Squelch level"},{"id":"B","text":"CTCSS tone"},{"id":"C","text":"Repeater offset (shift)"},{"id":"D","text":"Deviation ratio"}],"correctId":"C","rationale":"The repeater offset (or shift) is the fixed spacing between the repeater's receive (input) and transmit (output) frequencies, allowing it to listen and retransmit at the same time without self-interference. Squelch mutes weak signals, CTCSS is a sub-audible access tone, and deviation relates to FM modulation depth.","optionNotes":{"A":"Squelch sets the threshold for muting noise/weak signals, not the frequency spacing.","B":"CTCSS is a tone used to access a repeater, not the frequency difference.","D":"Deviation ratio describes FM modulation, not repeater frequency spacing."},"reference":"Radio Systems › Repeaters"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"MEDIUM","prompt":"Compared to analog FM voice, which is a primary advantage of digital voice modulation (e.g., P25 or DMR) for embassy tactical radio?","options":[{"id":"A","text":"It always uses less spectrum bandwidth than any analog mode"},{"id":"B","text":"It degrades gracefully with gradual static as signal weakens"},{"id":"C","text":"It supports built-in encryption and error correction for clearer, more secure audio near the coverage edge"},{"id":"D","text":"It eliminates the need for any antenna tuning"}],"correctId":"C","rationale":"Digital voice systems can apply forward error correction and standardized encryption, maintaining intelligible, secure audio until the signal drops below threshold. Unlike analog FM, which fades into gradual static, digital tends to fail abruptly ('cliff effect') rather than degrading gracefully, and bandwidth savings depend on the specific mode.","optionNotes":{"A":"Bandwidth depends on the protocol; digital is not always narrower than analog.","B":"Graceful static degradation is characteristic of analog FM; digital exhibits an abrupt cliff effect.","D":"Antenna tuning is unrelated to whether modulation is analog or digital."},"reference":"Radio Systems › Modulation"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"MEDIUM","prompt":"An embassy installs a VSAT terminal for backup connectivity using a geostationary satellite. Which inherent characteristic most affects interactive applications like VoIP over this link?","options":[{"id":"A","text":"Roughly 500-600 ms round-trip propagation latency"},{"id":"B","text":"Inability to carry IP traffic"},{"id":"C","text":"Immunity to rain fade"},{"id":"D","text":"Requirement to use HF frequencies"}],"correctId":"A","rationale":"A geostationary satellite sits about 35,786 km above the equator, so a signal must travel up and back down, producing roughly 250-300 ms one-way and ~500-600 ms round-trip latency that noticeably impairs interactive voice. Geostationary VSAT does carry IP, operates in microwave bands (Ku/Ka/C), and is in fact susceptible to rain fade.","optionNotes":{"B":"VSAT readily carries IP traffic; that is its main purpose.","C":"Ku/Ka-band VSAT is notably vulnerable to rain fade, not immune.","D":"Satellite uplinks use microwave (SHF/EHF) bands, not HF."},"reference":"Radio Systems › Satellite/SATCOM"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"HARD","prompt":"A communications officer must coordinate a new repeater frequency pair to avoid interfering with host-nation and allied services. Which document or process most directly governs which frequencies a diplomatic post may transmit on in the host country?","options":[{"id":"A","text":"The post's internal IP address allocation plan"},{"id":"B","text":"Host-nation spectrum authorization combined with international/ITU frequency coordination"},{"id":"C","text":"The radio manufacturer's warranty terms"},{"id":"D","text":"The embassy's physical security perimeter survey"}],"correctId":"B","rationale":"Transmitting in a host country requires authorization from that nation's spectrum regulator, consistent with ITU regional allocations and bilateral coordination, to prevent harmful interference. IP allocation, warranties, and physical security surveys do not determine permitted RF frequencies.","optionNotes":{"A":"IP addressing is a data-network concern, unrelated to RF spectrum rights.","C":"Warranty terms have no bearing on legal transmit authorization.","D":"A perimeter survey addresses physical security, not frequency licensing."},"reference":"Radio Systems › Frequency coordination"},
{"section":"JOB_KNOWLEDGE","topic":"Radio Systems","difficulty":"HARD","prompt":"During an emergency evacuation, an embassy needs the most robust portable antenna for short-to-medium range HF coverage that fills in the skip zone with high-angle radiation (NVIS). Which antenna characteristic is most appropriate?","options":[{"id":"A","text":"A high-gain dish aimed at the horizon"},{"id":"B","text":"A low horizontal dipole mounted close to the ground for near-vertical incidence skywave"},{"id":"C","text":"A vertical whip optimized for low-angle, very long-distance hops"},{"id":"D","text":"A Yagi beam pointed straight down at the soil"}],"correctId":"B","rationale":"Near-Vertical Incidence Skywave (NVIS) uses a low horizontal dipole that radiates energy steeply upward; the ionosphere reflects it back down to fill in coverage for roughly 0-400 km, eliminating the skip zone. A horizon-aimed dish and a low-angle vertical favor long-distance paths, and a downward-pointed Yagi is not a practical configuration.","optionNotes":{"A":"A horizon-aimed dish serves point-to-point microwave, not omnidirectional HF NVIS fill-in.","C":"A vertical whip favors low-angle long-haul hops and leaves a skip zone at medium range.","D":"Pointing a Yagi at the ground is not a recognized effective NVIS technique."},"reference":"Radio Systems › Antennas"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"EASY","prompt":"In a VoIP deployment, which protocol is responsible for setting up, modifying, and tearing down call sessions between endpoints?","options":[{"id":"A","text":"RTP"},{"id":"B","text":"SIP"},{"id":"C","text":"SNMP"},{"id":"D","text":"SMTP"}],"correctId":"B","rationale":"SIP (Session Initiation Protocol) is the signaling protocol that establishes, modifies, and terminates VoIP sessions. RTP carries the actual media stream once a call is set up, SNMP is for network management, and SMTP is for email.","optionNotes":{"A":"RTP transports the audio/video media, not the call-control signaling.","C":"SNMP manages network devices and has no role in call setup.","D":"SMTP delivers email and is unrelated to voice signaling."},"reference":"PBX/VoIP › Signaling"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"EASY","prompt":"After a SIP call is established, which protocol actually carries the digitized voice media between the two endpoints?","options":[{"id":"A","text":"RTP (Real-time Transport Protocol)"},{"id":"B","text":"DHCP"},{"id":"C","text":"LDAP"},{"id":"D","text":"TFTP"}],"correctId":"A","rationale":"RTP transports real-time audio and video media streams once SIP has negotiated the session, typically over UDP. DHCP assigns IP addresses, LDAP is a directory protocol, and TFTP is often used to provision phone configs but does not carry voice.","optionNotes":{"B":"DHCP handles IP address assignment, not media transport.","C":"LDAP provides directory lookups, not voice streaming.","D":"TFTP can deliver phone firmware/config files but carries no live audio."},"reference":"PBX/VoIP › Media transport"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"Embassy staff report choppy audio where words are dropped during VoIP calls, while latency seems acceptable. Which impairment is the most likely cause, and what QoS mechanism most directly mitigates it?","options":[{"id":"A","text":"High jitter; mitigated by a jitter buffer at the receiving endpoint"},{"id":"B","text":"Excessive bandwidth; mitigated by adding more codecs"},{"id":"C","text":"Low latency; mitigated by disabling QoS"},{"id":"D","text":"DNS failure; mitigated by a longer ringback tone"}],"correctId":"A","rationale":"Variation in packet arrival times (jitter) causes audio to break up; a jitter buffer holds incoming packets briefly to smooth out timing variations before playback. Adding codecs, disabling QoS, or DNS changes do not address inter-packet timing variation.","optionNotes":{"B":"More bandwidth or codecs does not directly correct timing variation between packets.","C":"Disabling QoS would worsen, not fix, real-time audio quality.","D":"DNS and ringback tones are unrelated to mid-call audio choppiness."},"reference":"PBX/VoIP › Jitter/latency/packet loss"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"An embassy wants to maximize the number of concurrent VoIP calls over a constrained WAN link while accepting some loss of audio fidelity. Which codec choice best fits this goal?","options":[{"id":"A","text":"G.711, because it is uncompressed and uses about 64 kbps per call"},{"id":"B","text":"G.729, because it compresses voice to about 8 kbps per call"},{"id":"C","text":"Disabling all codecs to save bandwidth"},{"id":"D","text":"Using video codecs for audio-only calls"}],"correctId":"B","rationale":"G.729 uses compression to carry voice at roughly 8 kbps, dramatically increasing the number of concurrent calls on a limited link at the cost of some quality. G.711 is essentially uncompressed at ~64 kbps, codecs cannot simply be disabled for a call, and video codecs would increase, not reduce, bandwidth.","optionNotes":{"A":"G.711 at ~64 kbps maximizes quality but minimizes call density on a constrained link.","C":"A call cannot proceed without a codec to encode the audio.","D":"Video codecs consume far more bandwidth, defeating the goal."},"reference":"PBX/VoIP › Codecs"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"HARD","prompt":"An IP-PBX at the embassy must place calls to ordinary landline and mobile numbers in the host country. Which component bridges the IP-based voice network to the traditional circuit-switched PSTN?","options":[{"id":"A","text":"A VoIP/PSTN media gateway"},{"id":"B","text":"A Layer 2 unmanaged switch"},{"id":"C","text":"A DNS resolver"},{"id":"D","text":"A RADIUS server"}],"correctId":"A","rationale":"A VoIP/PSTN gateway converts between IP packetized voice (RTP/SIP) and the TDM circuit-switched signaling of the PSTN, enabling calls to legacy phone numbers. An unmanaged switch only forwards Ethernet frames, DNS resolves names, and RADIUS handles authentication.","optionNotes":{"B":"An unmanaged switch forwards frames within the LAN and performs no protocol conversion.","C":"DNS maps names to addresses and does not interface with the PSTN.","D":"RADIUS provides AAA services, not voice protocol conversion."},"reference":"PBX/VoIP › Gateways"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"HARD","prompt":"To improve voice quality on a converged LAN carrying both data and VoIP, an administrator marks voice packets so switches and routers prioritize them. Which marking field and approach is standard for this Layer 3 prioritization?","options":[{"id":"A","text":"Setting the TTL field to a higher value on voice packets"},{"id":"B","text":"Using DSCP markings (e.g., EF) in the IP header to place voice in a priority queue"},{"id":"C","text":"Changing the source MAC address of each phone"},{"id":"D","text":"Increasing the MTU to 9000 bytes for all voice traffic"}],"correctId":"B","rationale":"Differentiated Services Code Point (DSCP) markings in the IP header, with Expedited Forwarding (EF) commonly used for voice, let routers and switches classify and place latency-sensitive traffic into a strict-priority/low-latency queue. TTL governs hop count, MAC changes do not signal priority, and jumbo MTU does not prioritize real-time voice.","optionNotes":{"A":"TTL limits how many hops a packet survives; it does not prioritize traffic.","C":"Spoofing MAC addresses does not convey QoS priority.","D":"Large MTUs can actually increase serialization delay for small voice packets."},"reference":"PBX/VoIP › QoS"},
{"section":"JOB_KNOWLEDGE","topic":"PBX / VoIP Convergence","difficulty":"MEDIUM","prompt":"An embassy replaces individual analog phone lines with a single SIP trunk to its provider. What is the primary benefit of a SIP trunk over traditional analog or PRI lines?","options":[{"id":"A","text":"It delivers multiple concurrent voice channels over the existing IP/data connection, scaling without new physical lines"},{"id":"B","text":"It guarantees calls work during a total internet outage"},{"id":"C","text":"It eliminates the need for any dialing plan"},{"id":"D","text":"It converts all calls to HF radio automatically"}],"correctId":"A","rationale":"A SIP trunk carries multiple simultaneous voice sessions over the IP data connection, so capacity can be added in software rather than by installing new physical circuits. It does depend on internet/IP connectivity (so it does not survive a full outage), still requires a dial plan, and has nothing to do with HF radio.","optionNotes":{"B":"SIP trunks rely on IP connectivity and fail during a full internet outage.","C":"A dial plan is still required to route calls.","D":"SIP trunking has no relationship to HF radio conversion."},"reference":"PBX/VoIP › SIP trunks"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"EASY","prompt":"Which HTTP method is conventionally used to retrieve a resource without modifying server state, and is considered safe and idempotent?","options":[{"id":"A","text":"POST"},{"id":"B","text":"GET"},{"id":"C","text":"DELETE"},{"id":"D","text":"PATCH"}],"correctId":"B","rationale":"GET is defined as a safe method that retrieves data without side effects and is idempotent (repeating it yields the same result). POST is neither safe nor idempotent, DELETE changes state (though idempotent), and PATCH applies partial modifications and is not guaranteed idempotent.","optionNotes":{"A":"POST creates/submits data and is not safe or reliably idempotent.","C":"DELETE removes a resource, so it changes server state.","D":"PATCH partially updates a resource and is not guaranteed idempotent."},"reference":"Systems Integration › HTTP methods/idempotency"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"EASY","prompt":"A developer integrating an embassy visa system needs a lightweight, human-readable data format that is natively easy to parse in JavaScript and widely used by REST APIs. Which format fits best?","options":[{"id":"A","text":"JSON"},{"id":"B","text":"CSV"},{"id":"C","text":"YAML"},{"id":"D","text":"Protocol Buffers"}],"correctId":"A","rationale":"JSON (JavaScript Object Notation) is a lightweight, text-based, human-readable format with native support in JavaScript and is the de facto standard payload for REST APIs. CSV lacks nested structure, YAML is common for config rather than API payloads, and Protocol Buffers is a compact binary (not human-readable) format.","optionNotes":{"B":"CSV is flat and cannot easily represent nested/hierarchical data.","C":"YAML is human-readable but is used mainly for configuration, not typical REST payloads.","D":"Protocol Buffers is a binary serialization format, not human-readable."},"reference":"Systems Integration › Data formats"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"An external partner system needs to be notified immediately whenever a new case is created in the embassy's application, without repeatedly polling. Which integration pattern best meets this requirement?","options":[{"id":"A","text":"A webhook that POSTs an event payload to the partner's callback URL"},{"id":"B","text":"A nightly batch ETL export"},{"id":"C","text":"The partner polling a GET endpoint every few seconds"},{"id":"D","text":"A static file shared over SFTP once a week"}],"correctId":"A","rationale":"A webhook pushes an HTTP callback (typically a POST) to a registered URL the moment an event occurs, giving near real-time notification without polling. Batch ETL and weekly file drops are delayed, and continuous polling is inefficient and not truly event-driven.","optionNotes":{"B":"Nightly batch introduces up to a day of latency, not immediate notification.","C":"Frequent polling wastes resources and still lags the event.","D":"Weekly SFTP transfers are far from real-time."},"reference":"Systems Integration › Webhooks"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"MEDIUM","prompt":"Two embassy applications must exchange messages reliably even when the receiving system is temporarily offline. Which middleware component best provides this decoupled, asynchronous, store-and-forward delivery?","options":[{"id":"A","text":"A message queue (e.g., RabbitMQ or a JMS broker)"},{"id":"B","text":"A synchronous REST call with no retry"},{"id":"C","text":"A read-only data warehouse"},{"id":"D","text":"A client-side JavaScript framework"}],"correctId":"A","rationale":"A message queue stores messages durably and delivers them when the consumer is available, decoupling producers from consumers and tolerating downtime. A single synchronous REST call fails if the receiver is offline, a data warehouse is for analytics, and a front-end framework is unrelated to backend messaging.","optionNotes":{"B":"A synchronous call without retry fails outright if the receiver is down.","C":"A data warehouse stores analytical data, not transactional message delivery.","D":"A JS framework runs in the browser and does not buffer inter-service messages."},"reference":"Systems Integration › Message queues"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"An embassy single sign-on setup must let a user authenticate once and access multiple web applications, with the identity provider asserting the user's identity via signed XML assertions. Which standard is designed for this browser-based web SSO?","options":[{"id":"A","text":"SAML"},{"id":"B","text":"OAuth 2.0 client credentials grant"},{"id":"C","text":"Basic authentication"},{"id":"D","text":"WPA2-Enterprise"}],"correctId":"A","rationale":"SAML (Security Assertion Markup Language) uses signed XML assertions exchanged between an identity provider and service providers to enable web browser single sign-on. OAuth 2.0 is primarily an authorization framework (and the client credentials grant is for machine-to-machine, not user SSO), Basic auth simply sends credentials per request, and WPA2-Enterprise secures Wi-Fi.","optionNotes":{"B":"OAuth 2.0 handles delegated authorization; the client credentials grant is machine-to-machine, not user web SSO.","C":"Basic authentication transmits credentials on each request and provides no SSO assertions.","D":"WPA2-Enterprise authenticates wireless network access, not web application SSO."},"reference":"Systems Integration › Authentication OAuth/SAML"},
{"section":"JOB_KNOWLEDGE","topic":"Systems Integration","difficulty":"HARD","prompt":"A legacy embassy financial system exposes a SOAP web service. Which characteristic is most accurate when contrasting SOAP with a typical REST API?","options":[{"id":"A","text":"SOAP relies on a formal WSDL contract and XML envelopes, with built-in standards like WS-Security"},{"id":"B","text":"SOAP can only return data in JSON"},{"id":"C","text":"SOAP cannot operate over HTTP under any circumstances"},{"id":"D","text":"REST mandates a strict XML schema for every response"}],"correctId":"A","rationale":"SOAP is a protocol that uses XML message envelopes, is typically described by a WSDL contract, and offers built-in extensions such as WS-Security and WS-ReliableMessaging. REST is an architectural style that is format-flexible (commonly JSON), and SOAP commonly runs over HTTP, so the other statements are false.","optionNotes":{"B":"SOAP messages are XML-based, not JSON.","C":"SOAP frequently operates over HTTP (and can use other transports like SMTP).","D":"REST does not require XML; it commonly uses JSON and is format-agnostic."},"reference":"Systems Integration › REST/SOAP APIs"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"EASY","prompt":"Which of the following is the best example of unstructured data?","options":[{"id":"A","text":"A relational table of consular appointment records with typed columns"},{"id":"B","text":"A scanned PDF of a handwritten visa application and its photo"},{"id":"C","text":"A CSV export of passport issuance counts by month"},{"id":"D","text":"A spreadsheet with rows and labeled columns"}],"correctId":"B","rationale":"Unstructured data lacks a predefined schema or tabular model; scanned documents, images, and free-form text are classic examples. Relational tables, CSV exports, and labeled spreadsheets are structured data organized into rows and columns.","optionNotes":{"A":"A typed relational table is structured data with a defined schema.","C":"A CSV of counts by month is structured, tabular data.","D":"A labeled spreadsheet is structured rows-and-columns data."},"reference":"Data Analytics › Structured vs unstructured data"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"EASY","prompt":"In the traditional ETL process for loading an embassy reporting database, what does the 'T' stand for and what does it do?","options":[{"id":"A","text":"Transfer — moves files between servers"},{"id":"B","text":"Transform — cleans, formats, and reshapes data before loading"},{"id":"C","text":"Truncate — empties the target tables"},{"id":"D","text":"Transmit — encrypts data in transit"}],"correctId":"B","rationale":"ETL stands for Extract, Transform, Load; the Transform step cleans, standardizes, deduplicates, and reshapes source data into the format required by the target system before loading. The other expansions are not what the 'T' in ETL denotes.","optionNotes":{"A":"Transfer is not the meaning of the T in ETL.","C":"Truncate is a table operation, not the ETL transformation phase.","D":"Transmit/encryption is unrelated to the ETL acronym."},"reference":"Data Analytics › ETL/ELT"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"An analyst wants to visualize the trend of monthly visa applications over the past three years to highlight changes over time. Which chart type is most appropriate?","options":[{"id":"A","text":"Pie chart"},{"id":"B","text":"Line chart"},{"id":"C","text":"Scatter plot of unrelated variables"},{"id":"D","text":"Single KPI gauge"}],"correctId":"B","rationale":"A line chart is the standard choice for showing a continuous trend of a metric over time, making increases and decreases easy to read. A pie chart shows part-to-whole composition at one point, a scatter plot examines correlation between two variables, and a gauge shows a single current value.","optionNotes":{"A":"Pie charts show composition at a moment, not change over time.","C":"A scatter plot examines relationships between two variables, not a time trend.","D":"A gauge displays one current value, not a multi-year trend."},"reference":"Data Analytics › Visualization chart selection"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"MEDIUM","prompt":"An embassy builds a centralized repository that ingests raw logs, images, and JSON in their native formats with schema applied only when read. Which architecture does this describe?","options":[{"id":"A","text":"A data warehouse with strict schema-on-write"},{"id":"B","text":"A data lake using schema-on-read"},{"id":"C","text":"A single normalized OLTP table"},{"id":"D","text":"A spreadsheet pivot table"}],"correctId":"B","rationale":"A data lake stores raw, diverse data (structured and unstructured) in native form and applies schema-on-read when the data is queried. A data warehouse enforces schema-on-write into a curated structure, an OLTP table is a transactional structure, and a pivot table is a small analytical view.","optionNotes":{"A":"A data warehouse enforces schema before loading (schema-on-write), the opposite of this description.","C":"An OLTP table is a structured transactional store, not a raw multi-format repository.","D":"A pivot table summarizes existing structured data, not raw native files."},"reference":"Data Analytics › Data warehouse vs lake"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"HARD","prompt":"An analyst reviewing appointment data finds one record with a wait time of 50,000 minutes among values that otherwise cluster between 5 and 60 minutes. Which statistical measure of central tendency is most resistant to this outlier's distortion?","options":[{"id":"A","text":"The arithmetic mean"},{"id":"B","text":"The median"},{"id":"C","text":"The sum"},{"id":"D","text":"The range"}],"correctId":"B","rationale":"The median is the middle value of ordered data and is robust to extreme outliers, so a single 50,000-minute value barely shifts it. The mean is pulled strongly toward the outlier, the sum is heavily inflated by it, and the range (max minus min) is a measure of spread that is extremely sensitive to outliers.","optionNotes":{"A":"The mean is highly sensitive to extreme values and would be skewed upward.","C":"The sum is not a measure of central tendency and is inflated by the outlier.","D":"The range measures spread, not central tendency, and is dominated by the outlier."},"reference":"Data Analytics › Basic statistics"},
{"section":"JOB_KNOWLEDGE","topic":"Data Analytics","difficulty":"HARD","prompt":"During a data-quality review of a consular database, an analyst finds the same applicant entered twice with slightly different spellings of their name. Which data-quality dimension is most directly violated, and what remediation technique addresses it?","options":[{"id":"A","text":"Timeliness; fixed by refreshing the dashboard"},{"id":"B","text":"Uniqueness; fixed by deduplication / record matching (entity resolution)"},{"id":"C","text":"Confidentiality; fixed by encrypting the column"},{"id":"D","text":"Availability; fixed by adding more storage"}],"correctId":"B","rationale":"Duplicate records for the same real-world entity violate the uniqueness dimension of data quality; deduplication and record matching (entity resolution) consolidate the duplicates. Timeliness concerns data freshness, confidentiality is a security property, and availability concerns access/uptime, none of which describe duplicate records.","optionNotes":{"A":"Timeliness is about how current data is, not duplication.","C":"Confidentiality is a security concern, unrelated to duplicate entries.","D":"Availability concerns access and uptime, not record duplication."},"reference":"Data Analytics › Data quality"}
] as const;

export const SITUATIONAL_EXTRA = [
{"section":"SITUATIONAL_JUDGMENT","topic":"Crisis Response","difficulty":"MEDIUM","scenario":"At 2 a.m. during a period of regional unrest, the embassy's primary internet circuit fails and the emergency notification system used to alert American citizens cannot send messages. You are the on-call IT officer and have a documented failover procedure to the backup satellite circuit.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Wait until the next business day so the full team can be briefed before changing anything"},{"id":"B","text":"Execute the documented failover to the backup satellite circuit to restore the notification system, then notify the duty officer and your supervisor of the outage and actions taken"},{"id":"C","text":"Email the ISP to demand they fix the primary circuit and wait for their response before acting"},{"id":"D","text":"Reroute traffic through your personal mobile hotspot to get the system online quickly"}],"correctId":"B","rationale":"Restoring the citizen-alert system during unrest is a safety-critical priority, and you have established authority to execute the documented failover. Acting on the approved procedure and immediately escalating balances urgency with proper communication.","optionNotes":{"A":"Delays a safety-critical system during an active crisis.","C":"Cedes control to an external party and leaves citizens unreachable.","D":"Routes sensitive traffic over an unauthorized, insecure personal device."},"reference":"Situational Judgment › Crisis prioritization"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Crisis Response","difficulty":"HARD","scenario":"During a developing security incident, the Regional Security Officer asks you to immediately shut down all embassy network connectivity. Doing so would also sever the classified comms link the front office is using to coordinate the evacuation of staff from an outlying consulate.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Comply instantly and shut everything down, since the RSO outranks you on security matters"},{"id":"B","text":"Refuse until you receive written authorization from the Chief of Mission"},{"id":"C","text":"Quickly flag to the RSO the live evacuation dependency on the classified link, propose isolating the compromised segment instead, and execute the agreed scope"},{"id":"D","text":"Shut down the unclassified network but quietly leave everything else running without telling anyone"}],"correctId":"C","rationale":"Safety of personnel and informed decision-making both matter; surfacing the evacuation dependency lets the RSO make an informed call and proposing a scoped isolation preserves both security and the life-safety link. Blind compliance, flat refusal, or covert deviation all fail either safety or integrity.","optionNotes":{"A":"Acts on rank without surfacing a life-safety consequence the RSO may not know.","B":"Obstructs an urgent security directive with bureaucratic delay.","D":"Conceals a unilateral deviation from the directive."},"reference":"Situational Judgment › Crisis decision-making"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Crisis Response","difficulty":"MEDIUM","scenario":"A ransomware note appears on a shared file server in the embassy's unclassified network. Staff are still actively saving documents to it, and the encryption appears to be spreading to mapped drives.","prompt":"What is the BEST first action?","options":[{"id":"A","text":"Post a notice to the all-staff channel asking everyone to be careful and keep working"},{"id":"B","text":"Pay the ransom from the petty-cash fund to stop the spread quickly"},{"id":"C","text":"Immediately isolate the affected server from the network to contain the spread, then notify the ISSO/cyber chain per incident response policy"},{"id":"D","text":"Reboot the server and run a quick antivirus scan to see if it clears on its own"}],"correctId":"C","rationale":"Containment to stop lateral spread is the recognized first step, followed by escalation to the security officer per incident-response procedure. Paying ransom, rebooting, or merely warning staff fail to contain the threat and bypass required reporting.","optionNotes":{"A":"Leaves the infection spreading and takes no containment action.","B":"Unauthorized, against policy, and rewards the attacker.","D":"A reboot can worsen damage and destroys forensic evidence."},"reference":"Situational Judgment › Incident containment"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Crisis Response","difficulty":"HARD","scenario":"A magnitude-7 earthquake has damaged the embassy. The primary data center is partially flooded, leadership is dispersed, and you are the senior IT person reachable. Multiple systems are degraded and you cannot restore all of them at once.","prompt":"How should you prioritize restoration?","options":[{"id":"A","text":"Restore the systems that are easiest and fastest to bring back first to show quick progress"},{"id":"B","text":"Restore emergency communications and life-safety systems first, then mission-critical systems, documenting decisions and reporting status up the chain as you go"},{"id":"C","text":"Wait for written guidance from Washington before restoring anything to avoid making a wrong call"},{"id":"D","text":"Restore the email and scheduling systems first since those generate the most user complaints"}],"correctId":"B","rationale":"In a disaster, restoration priority follows mission impact and life-safety, not ease or complaint volume. Documenting and reporting status keeps leadership informed while you act decisively within your role.","optionNotes":{"A":"Optimizes for visible progress over actual mission and safety impact.","C":"Paralysis while life-safety systems stay down.","D":"Prioritizes convenience and complaints over emergency and life-safety needs."},"reference":"Situational Judgment › Crisis prioritization"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Crisis Response","difficulty":"EASY","scenario":"You discover that a power surge has taken the embassy's visa-processing system offline during peak appointment hours, with a waiting room full of applicants.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Quietly try fixes on your own and hope it is back before anyone important notices"},{"id":"B","text":"Begin troubleshooting per the outage runbook and promptly notify the consular section and your supervisor of the outage and estimated impact"},{"id":"C","text":"Tell the consular chief it is their problem to manage the applicants while you work"},{"id":"D","text":"Send all applicants home immediately without consulting the consular section"}],"correctId":"B","rationale":"Acting on the runbook while promptly informing the affected section and supervisor balances action with appropriate communication. Hiding the problem, dumping it on others, or unilaterally turning away applicants all fail proper coordination.","optionNotes":{"A":"Conceals an outage with real public impact.","C":"Dumps the problem without coordinating a joint response.","D":"A unilateral decision outside your authority affecting consular operations."},"reference":"Situational Judgment › Outage communication"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Diplomatic Problem-Solving","difficulty":"MEDIUM","scenario":"A senior officer publicly criticizes your team in a staff meeting, claiming the help desk is incompetent because their laptop has been slow for a week. You know the slowness is caused by an unapproved application the officer installed themselves.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Correct the officer on the spot in front of the room to set the record straight"},{"id":"B","text":"Say nothing and let the team absorb the blame to avoid conflict with a senior officer"},{"id":"C","text":"Acknowledge the concern in the meeting, then follow up privately to diagnose the issue and explain the unapproved-software policy constructively"},{"id":"D","text":"File a formal complaint against the officer for the policy violation"}],"correctId":"C","rationale":"Constructive, private resolution preserves the relationship and the officer's dignity while still addressing the root cause and the policy. Public correction damages relationships, silence harms the team unfairly, and a formal complaint is disproportionate to a first issue.","optionNotes":{"A":"Public confrontation embarrasses the officer and damages the relationship.","B":"Lets a false impression stand and demoralizes the team.","D":"Escalates disproportionately before any direct, constructive conversation."},"reference":"Situational Judgment › Constructive feedback"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Diplomatic Problem-Solving","difficulty":"HARD","scenario":"Two sections, Consular and Political, both insist their project is the embassy's top IT priority and each has lobbied you separately. Their deadlines conflict and you cannot fully satisfy both with current staff.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Quietly favor the Political section because their chief is more senior and influential"},{"id":"B","text":"Bring the conflict and your resource constraints to the front office (or governance board) with options and a recommendation, and let leadership set the priority"},{"id":"C","text":"Promise both sections you will meet their deadlines and hope you can find a way"},{"id":"D","text":"Tell both sections to resolve it between themselves and proceed once they agree"}],"correctId":"B","rationale":"Cross-section priority conflicts that exceed your resources belong to mission leadership, who can weigh competing mission impact. Presenting options with a recommendation supports a fair decision rather than favoritism, false promises, or abdication.","optionNotes":{"A":"Decides on influence rather than mission impact, undermining integrity.","C":"Overpromises, setting up failure and lost trust on both sides.","D":"Abdicates a prioritization decision that leadership is positioned to make."},"reference":"Situational Judgment › Competing priorities"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Diplomatic Problem-Solving","difficulty":"MEDIUM","scenario":"A host-government ministry contact, with whom the embassy has a valued relationship, asks you informally to help troubleshoot their own ministry's email server as a favor, outside any formal agreement.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Help them directly since maintaining good relations with the host government is important"},{"id":"B","text":"Politely decline involvement, explain you cannot work on external systems without proper authorization, and refer the request to the appropriate embassy channel"},{"id":"C","text":"Quietly remote into their server after hours so no one at the embassy needs to know"},{"id":"D","text":"Refuse bluntly and tell them the embassy does not do favors"}],"correctId":"B","rationale":"Working on an external government's systems without authorization creates security, legal, and conflict-of-interest risks, but the relationship still warrants a courteous, constructive redirect. A polite decline with a proper referral protects both interests; covert help or a blunt refusal damages security or the relationship.","optionNotes":{"A":"Unauthorized work on a foreign system carries serious security and legal risk.","C":"Conceals unauthorized access to an external system.","D":"Needlessly harms a valued diplomatic relationship."},"reference":"Situational Judgment › Authorization boundaries"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Diplomatic Problem-Solving","difficulty":"EASY","scenario":"A locally employed staff member repeatedly submits tickets that are vague and missing key details, slowing the help desk down. They are hardworking but new to the embassy's ticketing system.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Close their vague tickets without action until they learn to submit them correctly"},{"id":"B","text":"Privately coach the staff member, show them how to include the needed details, and share a quick-reference guide"},{"id":"C","text":"Send an all-staff email criticizing poorly written tickets so they get the message"},{"id":"D","text":"Escalate to their supervisor that the staff member is creating problems"}],"correctId":"B","rationale":"A private, capability-building coaching response helps the staff member improve while preserving the relationship. Closing tickets, public criticism, or premature escalation are punitive and miss the genuine training need.","optionNotes":{"A":"Punitive and leaves the actual IT issues unresolved.","C":"Public shaming over a fixable knowledge gap.","D":"Escalates before any direct, supportive coaching."},"reference":"Situational Judgment › Coaching staff"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Diplomatic Problem-Solving","difficulty":"HARD","scenario":"A vendor delivering a critical networking upgrade has fallen badly behind, and their on-site engineer has been giving you reassurances that you now suspect are inaccurate. The project sponsor in the front office still believes things are on track based on the vendor's reports.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Keep relaying the vendor's optimistic updates upward to avoid alarming the front office prematurely"},{"id":"B","text":"Independently verify the actual project status, document the discrepancies, and give the sponsor an accurate assessment along with options to recover the schedule"},{"id":"C","text":"Confront the vendor engineer aggressively and threaten to cancel the contract"},{"id":"D","text":"Quietly start doing the vendor's work yourself to hide the delay from leadership"}],"correctId":"B","rationale":"Integrity requires giving leadership an accurate, documented picture rather than passing along reassurances you doubt, and offering recovery options is constructive. Concealing the delay, doing the vendor's work covertly, or making threats all fail honesty, proper process, or the relationship.","optionNotes":{"A":"Passes on information you believe is false, misleading leadership.","C":"Adversarial overreaction that skips verification and damages the relationship.","D":"Conceals the real status and assumes work outside your role."},"reference":"Situational Judgment › Vendor management"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Resource Prioritization","difficulty":"MEDIUM","scenario":"On the same morning you receive: a request to set up a projector for the Ambassador's noon meeting, a report that the classified network printer is jammed, a password reset for an officer locked out before a deadline, and a routine request to relabel some equipment.","prompt":"Which should you address FIRST?","options":[{"id":"A","text":"The Ambassador's projector, because the request comes from the highest-ranking person"},{"id":"B","text":"The officer's password reset, since it is quick and blocks them from working before a deadline"},{"id":"C","text":"Triage by impact and urgency, handling the password reset that is blocking time-sensitive work first while scheduling the others appropriately"},{"id":"D","text":"The equipment relabeling, because it is the fastest to clear off your list"}],"correctId":"C","rationale":"Good prioritization weighs mission impact and urgency rather than rank or ease, and a blocking, time-sensitive password reset typically has the highest immediate impact. Choosing by rank or by what is quickest to clear ignores the actual urgency of competing tasks.","optionNotes":{"A":"Prioritizes by rank rather than impact and urgency.","B":"Right task but for the wrong reason (speed, not a deliberate triage).","D":"Optimizes for clearing the list, not mission impact."},"reference":"Situational Judgment › Triage by impact"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Resource Prioritization","difficulty":"HARD","scenario":"A critical security patch must be deployed to the embassy's servers to close an actively exploited vulnerability, but applying it requires a reboot that will take a key consular system offline during business hours. The consular section objects to any daytime downtime.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Delay the patch indefinitely until the consular section is comfortable with the timing"},{"id":"B","text":"Apply the patch immediately during business hours without coordinating, since security comes first"},{"id":"C","text":"Assess the exploitation risk; if it can wait briefly, coordinate an expedited maintenance window through change management while applying interim mitigations, and escalate if consular still blocks a necessary fix"},{"id":"D","text":"Skip the patch and rely on the firewall to block any attacks"}],"correctId":"C","rationale":"An actively exploited vulnerability is urgent, but proper change management and coordination minimize mission disruption; interim mitigations bridge the gap and escalation resolves a standoff that risks security. Indefinite delay and skipping the patch ignore security; an uncoordinated daytime reboot needlessly disrupts the mission when coordination is feasible.","optionNotes":{"A":"Leaves an actively exploited hole open at the section's convenience.","B":"Skips change management and disrupts the mission without coordination.","D":"Accepts a known, exploited risk with an inadequate compensating control."},"reference":"Situational Judgment › Patching vs availability"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Resource Prioritization","difficulty":"MEDIUM","scenario":"Your small IT team is fully booked for the week on a planned migration. The management officer asks you to also take on a non-urgent, time-consuming upgrade of the conference room AV by Friday.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Agree to do it all and quietly push your team to work unpaid overtime to fit it in"},{"id":"B","text":"Refuse the request outright because your team is already busy"},{"id":"C","text":"Explain the current workload and trade-offs, and work with the management officer to reprioritize or reschedule based on what matters most to the mission"},{"id":"D","text":"Quietly drop part of the migration to make room, without telling anyone"}],"correctId":"C","rationale":"Transparent discussion of trade-offs lets leadership make an informed reprioritization decision and protects both deliverables and the team. Overcommitting, flat refusal, or silently dropping committed work all fail either capacity realism or transparency.","optionNotes":{"A":"Overcommits and burns out the team to avoid a hard conversation.","B":"Unhelpful refusal with no attempt to find a workable path.","D":"Silently sacrifices committed work, undermining trust."},"reference":"Situational Judgment › Capacity and trade-offs"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Resource Prioritization","difficulty":"EASY","scenario":"You have a limited budget remaining for the fiscal year and several pending requests: replacing aging, failure-prone laptops for officers, buying a nicer monitor for your own desk, and stocking spare cables.","prompt":"What is the BEST way to allocate the funds?","options":[{"id":"A","text":"Buy yourself the nicer monitor first since you work hard and deserve it"},{"id":"B","text":"Prioritize replacing the failure-prone laptops that pose the greatest risk to mission productivity, then essential spares"},{"id":"C","text":"Split the budget evenly across all three requests regardless of impact"},{"id":"D","text":"Spend the entire budget on spare cables to avoid ever running out"}],"correctId":"B","rationale":"Allocating limited funds by mission impact addresses the greatest operational risk first. Self-interest, even splitting, or over-buying low-impact items all misallocate scarce resources.","optionNotes":{"A":"Self-serving use of mission funds over operational need.","C":"Ignores differing impact, underfunding the most critical need.","D":"Overspends on a low-impact item while real risks go unaddressed."},"reference":"Situational Judgment › Budget allocation"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Resource Prioritization","difficulty":"HARD","scenario":"Mid-migration, you realize you underestimated the effort and will miss the committed cutover date. Finishing on time would require skipping the backup-and-rollback steps. Leadership is expecting completion on schedule.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Skip the backups and rollback plan to make the deadline, since the migration will probably succeed"},{"id":"B","text":"Proactively inform leadership that the schedule is at risk, present a realistic revised timeline that keeps backups and rollback intact, and recommend the safer path"},{"id":"C","text":"Quietly slip the date and explain only if someone asks"},{"id":"D","text":"Push through on time and, if it fails, deal with the consequences afterward"}],"correctId":"B","rationale":"Integrity and risk management require informing leadership early and protecting safeguards like backups and rollback, even at the cost of the date. Skipping safeguards or pushing through risks data loss, and quietly slipping the date conceals a material schedule change.","optionNotes":{"A":"Sacrifices essential data-protection safeguards to hit a date.","C":"Conceals a material schedule slip from leadership.","D":"Gambles mission data on hitting a deadline with no recovery path."},"reference":"Situational Judgment › Schedule integrity"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Interpersonal Judgment","difficulty":"MEDIUM","scenario":"A grateful contractor whose access you helped restore offers you an expensive bottle of liquor and tickets to a sold-out event as thanks. They emphasize it is purely personal and no one needs to know.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Accept the gift since it is a sincere personal thank-you and refusing would be rude"},{"id":"B","text":"Politely decline the gift, explain the ethics rules on accepting gifts from people you do business with, and if needed report the offer per policy"},{"id":"C","text":"Accept the tickets but decline the liquor as a reasonable compromise"},{"id":"D","text":"Accept the gift quietly but do not tell your supervisor to avoid any awkwardness"}],"correctId":"B","rationale":"Gift-acceptance rules exist to prevent conflicts of interest, especially with contractors you do business with; declining politely and reporting if required upholds integrity. Accepting any portion, or accepting quietly, creates or conceals a conflict of interest.","optionNotes":{"A":"Accepting a substantial gift from a contractor creates a conflict of interest.","C":"Still accepts a thing of value from a business contact.","D":"Concealment compounds the ethics violation."},"reference":"Situational Judgment › Gifts and ethics"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Interpersonal Judgment","difficulty":"HARD","scenario":"A well-liked colleague on your team confides that they have been using a personal USB drive to move work files between their home and office computers because it is more convenient. They ask you to keep it between the two of you.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Keep their confidence to preserve the friendship, since no harm seems to have occurred yet"},{"id":"B","text":"Tell them privately this violates security policy and poses a real risk, urge them to stop and self-report, and report it yourself through the proper channel if they will not"},{"id":"C","text":"Say nothing now but watch them closely to see if it happens again"},{"id":"D","text":"Report them immediately to the front office without speaking to them first"}],"correctId":"B","rationale":"Unauthorized data movement and personal media are serious security risks that must not be concealed; addressing it directly first respects the colleague while ensuring it gets reported. Staying silent or merely watching conceals a violation, while skipping straight to leadership forgoes a fair, direct conversation when reporting is still ensured.","optionNotes":{"A":"Conceals a genuine security violation to protect a friendship.","C":"Passive monitoring still leaves the violation unreported.","D":"Bypasses a fair direct conversation; reporting can follow if needed."},"reference":"Situational Judgment › Loyalty vs security"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Interpersonal Judgment","difficulty":"MEDIUM","scenario":"During an upgrade you accidentally delete a section's shared folder, then restore most of it from backup, but a few hours of recent work are unrecoverable. No one has noticed yet.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Say nothing since most data was recovered and the lost work may go unnoticed"},{"id":"B","text":"Promptly inform the affected section and your supervisor about the incident and the specific unrecoverable data, and help them recover or recreate it"},{"id":"C","text":"Quietly recreate what you can from memory and hope it is close enough"},{"id":"D","text":"Blame the backup system for the gap if anyone happens to ask"}],"correctId":"B","rationale":"Integrity requires promptly disclosing the data loss and helping affected users recover, even though it is uncomfortable. Concealing it, fabricating replacements, or shifting blame are dishonest and leave users working from incomplete or wrong data.","optionNotes":{"A":"Conceals real data loss that affects others' work.","C":"Substitutes guesses for real data, hiding the loss.","D":"Dishonest blame-shifting to avoid accountability."},"reference":"Situational Judgment › Owning mistakes"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Interpersonal Judgment","difficulty":"EASY","scenario":"Your supervisor publicly praises you for resolving a major outage, but a junior teammate actually did most of the diagnostic work that fixed it.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Accept the praise graciously since you led the team"},{"id":"B","text":"Acknowledge the junior teammate's key contribution to your supervisor and the team, giving them the credit they earned"},{"id":"C","text":"Say nothing publicly but mention it to the teammate privately so they feel appreciated"},{"id":"D","text":"Downplay the whole outage so the question of credit never comes up"}],"correctId":"B","rationale":"Integrity and good leadership mean giving accurate credit where it is due, which also builds the team. Quietly accepting the praise misrepresents the effort, and private-only acknowledgment or downplaying the work both withhold the recognition the teammate earned.","optionNotes":{"A":"Takes credit for another's work, however passively.","C":"Private thanks still lets the public record stay inaccurate.","D":"Distorts the facts to dodge the credit question."},"reference":"Situational Judgment › Giving credit"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Interpersonal Judgment","difficulty":"HARD","scenario":"An officer who outranks you insists you grant them administrator rights on their workstation so they can install software themselves, saying it will save everyone time. Policy reserves admin rights to IT, and the officer is becoming impatient and pulling rank.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Grant the admin rights to avoid friction with a senior officer"},{"id":"B","text":"Respectfully decline, explain the security policy and why admin rights are restricted, offer to install approved software quickly, and escalate to management if they keep pressing"},{"id":"C","text":"Refuse curtly and tell the officer that rules are rules, end of discussion"},{"id":"D","text":"Grant the rights temporarily and plan to quietly revoke them later"}],"correctId":"B","rationale":"Security policy on privileged access applies regardless of rank; declining respectfully while offering a fast compliant alternative resolves the underlying need without compromising security. Caving to rank, granting even temporary rights, or refusing curtly fail security or the relationship.","optionNotes":{"A":"Lets rank override a security control, creating real risk.","C":"Technically correct but needlessly damages the relationship.","D":"Still grants unauthorized privilege and adds covert revocation."},"reference":"Situational Judgment › Pressure and policy"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Security & Compliance","difficulty":"MEDIUM","scenario":"You notice that a file marked classified appears to have been saved by another user onto the embassy's unclassified network share. The user is not around and the file is still sitting there.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Delete the file yourself immediately so it stops being exposed, then move on"},{"id":"B","text":"Do not forward, copy, or open it further; immediately report the suspected spill to the ISSO/security officer and follow their data-spill remediation instructions"},{"id":"C","text":"Email the file back to the user with a note reminding them to be careful next time"},{"id":"D","text":"Leave it alone since it is not your file and not your responsibility"}],"correctId":"B","rationale":"A classified spill requires immediate reporting and controlled remediation by security staff, not ad hoc handling. Deleting it yourself can destroy needed information and bypass procedure, emailing it spreads the spill, and ignoring it leaves classified data exposed.","optionNotes":{"A":"Unilateral deletion bypasses required spill procedures and forensics.","C":"Emailing classified content further spreads the spill.","D":"Ignoring a known spill leaves classified data exposed."},"reference":"Situational Judgment › Data spill handling"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Security & Compliance","difficulty":"EASY","scenario":"You receive an email that appears to be from the embassy's IT help desk asking you to click a link and confirm your network password due to a 'security upgrade.' The sender address looks slightly off.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Click the link and enter your password to keep your account from being locked"},{"id":"B","text":"Do not click; report the suspected phishing email to the security/IT team using the established reporting method and delete it as instructed"},{"id":"C","text":"Forward it to several colleagues to warn them to be careful"},{"id":"D","text":"Ignore and delete it without telling anyone"}],"correctId":"B","rationale":"Reporting suspected phishing through the proper channel lets security investigate and protect others, which is the established procedure. Clicking compromises credentials, forwarding can spread the malicious content, and silent deletion leaves the threat unreported.","optionNotes":{"A":"Hands credentials to an attacker.","C":"Forwarding the live email risks others clicking it.","D":"Leaves security blind to an active phishing campaign."},"reference":"Situational Judgment › Phishing response"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Security & Compliance","difficulty":"HARD","scenario":"An officer returning from travel asks you to plug their personal smartphone into a classified-network workstation just to charge it, insisting it cannot connect to anything and it is only for power. They are in a hurry.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Allow it since charging over USB does not transfer data and they are in a rush"},{"id":"B","text":"Decline, explain that connecting any unauthorized personal device to a classified system is prohibited regardless of purpose, and point them to an approved charging option"},{"id":"C","text":"Allow it but only for a couple of minutes to minimize any risk"},{"id":"D","text":"Quietly do it for them this once to avoid an argument"}],"correctId":"B","rationale":"Connecting any unauthorized device to a classified system is prohibited because USB ports can transfer data and introduce risk regardless of intent. Allowing it for any duration, or doing it quietly, violates a firm security rule, while a clear explanation plus an approved alternative resolves the need safely.","optionNotes":{"A":"USB connections can move data; charging is not a safe exception.","C":"A short connection is still a prohibited connection.","D":"Knowingly breaks a security rule and conceals it."},"reference":"Situational Judgment › Unauthorized devices"},
{"section":"SITUATIONAL_JUDGMENT","topic":"Security & Compliance","difficulty":"MEDIUM","scenario":"During a routine audit you discover a former employee's network account is still active three months after their departure, and it appears to have been logged into last week. You are preparing the audit report.","prompt":"What is the BEST action?","options":[{"id":"A","text":"Quietly disable the account and leave it out of the report so the lapse does not reflect badly on the team"},{"id":"B","text":"Disable the account immediately, report the suspicious recent login to the security officer as a potential incident, and document the finding accurately in the audit"},{"id":"C","text":"Note it in the report but take no action until the audit is formally finished"},{"id":"D","text":"Reset the account's password and keep it active in case the former employee needs occasional access"}],"correctId":"B","rationale":"An active departed-employee account with a recent login is a security incident requiring immediate containment, escalation, and accurate documentation. Concealing it from the report falsifies the audit, deferring action leaves a live risk open, and keeping the account active is a clear policy violation.","optionNotes":{"A":"Omitting the finding falsifies the audit and hides a real incident.","C":"Documents but leaves an active, possibly compromised account open.","D":"Retaining a departed employee's access violates least-privilege policy."},"reference":"Situational Judgment › Access review integrity"}
] as const;

export const ENGLISH_EXTRA = [
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"EASY","prompt":"Choose the sentence that is grammatically correct.","options":[{"id":"A","text":"The team of analysts are reviewing the security report."},{"id":"B","text":"The team of analysts is reviewing the security report."},{"id":"C","text":"The team of analysts were reviewing the security report."},{"id":"D","text":"The team of analysts have reviewed the security report."}],"correctId":"B","rationale":"The subject is the singular collective noun \"team,\" so it takes a singular verb. The prepositional phrase \"of analysts\" does not change the number of the subject. \"Is reviewing\" agrees with \"team.\"","reference":"English › Subject–verb agreement"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"EASY","prompt":"Choose the grammatically correct sentence.","options":[{"id":"A","text":"Each of the delegates have submitted their credentials."},{"id":"B","text":"Each of the delegates submit their credentials."},{"id":"C","text":"Each of the delegates has submitted his or her credentials."},{"id":"D","text":"Each of the delegates were submitting their credentials."}],"correctId":"C","rationale":"The indefinite pronoun \"each\" is singular and requires a singular verb (\"has\") and singular pronoun reference (\"his or her\"). The phrase \"of the delegates\" does not govern the verb.","reference":"English › Agreement with indefinite pronouns"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"MEDIUM","prompt":"Which sentence uses the correct pronoun case?","options":[{"id":"A","text":"The director asked my colleague and I to lead the briefing."},{"id":"B","text":"The director asked my colleague and me to lead the briefing."},{"id":"C","text":"The director asked my colleague and myself to lead the briefing."},{"id":"D","text":"The director asked I and my colleague to lead the briefing."}],"correctId":"B","rationale":"As the object of the verb \"asked,\" the pronoun must be in the objective case: \"me.\" Removing \"my colleague and\" makes this clear (\"asked me\"). \"Myself\" is a reflexive pronoun and cannot serve as a plain object here.","reference":"English › Pronoun case"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"MEDIUM","prompt":"Choose the sentence with correct verb tense consistency.","options":[{"id":"A","text":"When the system detected the breach, it immediately alerts the duty officer."},{"id":"B","text":"When the system detects the breach, it immediately alerted the duty officer."},{"id":"C","text":"When the system detected the breach, it immediately alerted the duty officer."},{"id":"D","text":"When the system detect the breach, it immediately alert the duty officer."}],"correctId":"C","rationale":"Both clauses describe a single past event, so both verbs must be in the past tense: \"detected\" and \"alerted.\" Options A and B mix past and present tense inconsistently.","reference":"English › Verb tense consistency"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"HARD","prompt":"Which sentence correctly uses \"who\" or \"whom\"?","options":[{"id":"A","text":"The attaché whom presented the proposal will join the panel."},{"id":"B","text":"We must determine who the committee will appoint as liaison."},{"id":"C","text":"The candidate who we interviewed yesterday declined the post."},{"id":"D","text":"We must determine whom the committee will appoint as liaison."}],"correctId":"D","rationale":"\"Whom\" is correct because it functions as the object of the verb \"will appoint\" (the committee will appoint whom). In A, the subject of \"presented\" should be \"who\"; in C, the object of \"interviewed\" should be \"whom\"; B uses \"who\" where the object \"whom\" is needed.","reference":"English › Who vs. whom"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"HARD","prompt":"Choose the grammatically correct sentence.","options":[{"id":"A","text":"Neither the minister nor the aides was available for comment."},{"id":"B","text":"Neither the minister nor the aides were available for comment."},{"id":"C","text":"Neither the minister nor the aides is available for comment."},{"id":"D","text":"Neither the aides nor the minister were available for comment."}],"correctId":"B","rationale":"In \"neither...nor\" constructions, the verb agrees with the nearer subject. Here the nearer subject is the plural \"aides,\" so the verb must be plural: \"were.\" Option D incorrectly uses a plural verb with the nearer singular \"minister.\"","reference":"English › Subject–verb agreement"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"EASY","prompt":"Choose the grammatically correct sentence.","options":[{"id":"A","text":"There is several outstanding tickets in the queue."},{"id":"B","text":"There are several outstanding tickets in the queue."},{"id":"C","text":"There was several outstanding tickets in the queue."},{"id":"D","text":"There be several outstanding tickets in the queue."}],"correctId":"B","rationale":"In sentences beginning with \"there,\" the verb agrees with the real subject that follows. The subject \"tickets\" is plural, so the verb must be \"are.\"","reference":"English › Subject–verb agreement"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"MEDIUM","prompt":"Which sentence correctly maintains pronoun-antecedent agreement?","options":[{"id":"A","text":"Every employee must update their password before Friday."},{"id":"B","text":"Every employee must update its password before Friday."},{"id":"C","text":"Every employee must update his or her password before Friday."},{"id":"D","text":"Every employee must update they password before Friday."}],"correctId":"C","rationale":"\"Every employee\" is grammatically singular, so the matching pronoun in formal, traditional usage is the singular \"his or her.\" \"Its\" is for non-persons, and \"they password\" is ungrammatical.","reference":"English › Pronoun-antecedent agreement"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"MEDIUM","prompt":"Choose the best correction for the underlined part: \"The set of protocols that govern data exchange were updated last quarter.\"","options":[{"id":"A","text":"were updated"},{"id":"B","text":"was updated"},{"id":"C","text":"are updated"},{"id":"D","text":"have been update"}],"correctId":"B","rationale":"The subject is the singular noun \"set,\" not \"protocols,\" so the verb must be singular: \"was updated.\" The clause \"that govern data exchange\" modifies \"protocols\" but does not change the subject of the main verb.","reference":"English › Subject–verb agreement"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"HARD","prompt":"Choose the grammatically correct sentence.","options":[{"id":"A","text":"If I was the lead architect, I would prioritize encryption."},{"id":"B","text":"If I were the lead architect, I would prioritize encryption."},{"id":"C","text":"If I were the lead architect, I will prioritize encryption."},{"id":"D","text":"If I was the lead architect, I will prioritize encryption."}],"correctId":"B","rationale":"A hypothetical, contrary-to-fact condition requires the subjunctive \"were\" in the if-clause and \"would\" in the result clause. \"Was\" is indicative and incorrect here, and \"will\" does not match the conditional.","reference":"English › Subjunctive mood"},
{"section":"ENGLISH_EXPRESSION","topic":"Grammar","difficulty":"EASY","prompt":"Choose the grammatically correct sentence.","options":[{"id":"A","text":"The number of cyberattacks have risen sharply this year."},{"id":"B","text":"The number of cyberattacks has risen sharply this year."},{"id":"C","text":"A number of cyberattacks has risen sharply this year."},{"id":"D","text":"The number of cyberattacks are rising sharply this year."}],"correctId":"B","rationale":"\"The number\" is treated as singular and takes a singular verb (\"has risen\"). By contrast, \"a number of\" is plural, but that construction is not what appears in the correct option.","reference":"English › Subject–verb agreement"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"EASY","prompt":"Select the correctly punctuated sentence.","options":[{"id":"A","text":"After the summit concluded the delegates returned home."},{"id":"B","text":"After the summit concluded, the delegates returned home."},{"id":"C","text":"After the summit, concluded the delegates returned home."},{"id":"D","text":"After, the summit concluded the delegates returned home."}],"correctId":"B","rationale":"A comma should follow an introductory dependent clause (\"After the summit concluded\") to separate it from the main clause. The other placements interrupt the sentence at incorrect points.","reference":"English › Commas with introductory clauses"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"EASY","prompt":"Which sentence correctly uses an apostrophe?","options":[{"id":"A","text":"The ministry updated it's security policy."},{"id":"B","text":"The ministry updated its security policy."},{"id":"C","text":"The ministry updated its' security policy."},{"id":"D","text":"The ministry updated it security policy."}],"correctId":"B","rationale":"\"Its\" is the possessive form of \"it\" and takes no apostrophe. \"It's\" means \"it is\" or \"it has,\" and \"its'\" is never correct.","reference":"English › Apostrophes and possessives"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"MEDIUM","prompt":"Select the sentence that correctly avoids a comma splice.","options":[{"id":"A","text":"The server crashed at noon, the backup restored service within minutes."},{"id":"B","text":"The server crashed at noon the backup restored service within minutes."},{"id":"C","text":"The server crashed at noon; the backup restored service within minutes."},{"id":"D","text":"The server crashed at noon, however the backup restored service within minutes."}],"correctId":"C","rationale":"Two independent clauses may be joined by a semicolon. Option A is a comma splice, B is a run-on, and D incorrectly joins clauses with a comma before a conjunctive adverb that itself needs a semicolon before it.","reference":"English › Comma splices and semicolons"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"MEDIUM","prompt":"Which sentence uses the colon correctly?","options":[{"id":"A","text":"The audit covered three areas: access control, encryption, and logging."},{"id":"B","text":"The audit covered: access control, encryption, and logging."},{"id":"C","text":"The audit covered three areas, access control, encryption, and logging."},{"id":"D","text":"The audit covered three areas; access control, encryption, and logging."}],"correctId":"A","rationale":"A colon introduces a list only after a complete independent clause. \"The audit covered three areas\" is complete, so the colon is correct. In B the clause before the colon is incomplete; C and D use the wrong mark.","reference":"English › Colons"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"HARD","prompt":"Select the correctly punctuated sentence.","options":[{"id":"A","text":"The conference will be held in Geneva, Switzerland, and Vienna, Austria, next spring."},{"id":"B","text":"The conference will be held in Geneva, Switzerland and Vienna, Austria next spring."},{"id":"C","text":"The conference will be held in Geneva Switzerland, and Vienna Austria, next spring."},{"id":"D","text":"The conference will be held in Geneva, Switzerland, and Vienna Austria, next spring."}],"correctId":"A","rationale":"A comma is needed both before and after each country name that follows a city, and the items in the series are properly separated. Option A places commas correctly around \"Switzerland\" and \"Austria\" and after the final element before the closing phrase.","reference":"English › Commas with appositives and series"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"HARD","prompt":"Which sentence correctly uses semicolons in a complex series?","options":[{"id":"A","text":"The delegation included Maria Lopez, the lead negotiator, Tomas Reed, the legal adviser, and Aki Sato, the technical liaison."},{"id":"B","text":"The delegation included Maria Lopez, the lead negotiator; Tomas Reed, the legal adviser; and Aki Sato, the technical liaison."},{"id":"C","text":"The delegation included; Maria Lopez, the lead negotiator, Tomas Reed, the legal adviser, and Aki Sato, the technical liaison."},{"id":"D","text":"The delegation included Maria Lopez the lead negotiator; Tomas Reed the legal adviser; and Aki Sato the technical liaison."}],"correctId":"B","rationale":"When items in a series already contain internal commas, semicolons separate the items for clarity. Option B uses semicolons between the three people and commas within each appositive. Option A is ambiguous, C misplaces the semicolon, and D omits required internal commas.","reference":"English › Semicolons in series"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"EASY","prompt":"Which sentence correctly forms the plural possessive?","options":[{"id":"A","text":"The analysts' reports were submitted on time."},{"id":"B","text":"The analyst's reports were submitted on time, referring to several analysts."},{"id":"C","text":"The analysts's reports were submitted on time."},{"id":"D","text":"The analysts reports were submitted on time."}],"correctId":"A","rationale":"For a regular plural noun ending in -s, the possessive is formed by adding only an apostrophe: \"analysts'.\" This indicates that the reports belong to multiple analysts. The other options use incorrect or missing possessive forms.","reference":"English › Apostrophes and possessives"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"MEDIUM","prompt":"Select the sentence with correct hyphenation.","options":[{"id":"A","text":"They deployed a state of the art encryption system."},{"id":"B","text":"They deployed a state-of-the-art encryption system."},{"id":"C","text":"They deployed a state-of-the art encryption system."},{"id":"D","text":"They deployed a state of-the-art encryption system."}],"correctId":"B","rationale":"A compound adjective placed before the noun it modifies should be fully hyphenated: \"state-of-the-art encryption system.\" Option A omits the hyphens, and C and D hyphenate the phrase incompletely or incorrectly.","reference":"English › Hyphens in compound modifiers"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"MEDIUM","prompt":"Choose the correctly punctuated sentence.","options":[{"id":"A","text":"The proposal, which the board approved unanimously, takes effect in July."},{"id":"B","text":"The proposal which the board approved unanimously, takes effect in July."},{"id":"C","text":"The proposal, which the board approved unanimously takes effect in July."},{"id":"D","text":"The proposal which the board approved unanimously takes effect in July."}],"correctId":"A","rationale":"A nonrestrictive relative clause introduced by \"which\" must be set off by a pair of commas. Option A correctly brackets \"which the board approved unanimously\" with commas on both sides.","reference":"English › Commas with nonrestrictive clauses"},
{"section":"ENGLISH_EXPRESSION","topic":"Punctuation","difficulty":"HARD","prompt":"Which sentence correctly uses a semicolon with a conjunctive adverb?","options":[{"id":"A","text":"The patch was tested thoroughly, however, it failed in production."},{"id":"B","text":"The patch was tested thoroughly; however, it failed in production."},{"id":"C","text":"The patch was tested thoroughly however; it failed in production."},{"id":"D","text":"The patch was tested thoroughly, however it failed in production."}],"correctId":"B","rationale":"When a conjunctive adverb such as \"however\" joins two independent clauses, a semicolon precedes it and a comma follows it. Option A creates a comma splice, and C and D misplace the punctuation.","reference":"English › Semicolons with conjunctive adverbs"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"EASY","prompt":"Which sentence uses \"affect\" and \"effect\" correctly?","options":[{"id":"A","text":"The outage will affect productivity, but the effect should be temporary."},{"id":"B","text":"The outage will effect productivity, but the affect should be temporary."},{"id":"C","text":"The outage will affect productivity, but the affect should be temporary."},{"id":"D","text":"The outage will effect productivity, but the effect should be temporary."}],"correctId":"A","rationale":"\"Affect\" is usually a verb meaning to influence, and \"effect\" is usually a noun meaning a result. The outage will affect (verb) productivity, and the effect (noun) will be temporary.","reference":"English › Affect vs. effect"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"EASY","prompt":"Choose the sentence that uses the correct word.","options":[{"id":"A","text":"Their planning to migrate the database over the weekend."},{"id":"B","text":"There planning to migrate the database over the weekend."},{"id":"C","text":"They're planning to migrate the database over the weekend."},{"id":"D","text":"Theyre planning to migrate the database over the weekend."}],"correctId":"C","rationale":"\"They're\" is the contraction of \"they are,\" which the sentence requires. \"Their\" is possessive, \"there\" indicates place, and \"theyre\" is not a word.","reference":"English › Their, there, they're"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"EASY","prompt":"Which sentence uses \"fewer\" or \"less\" correctly?","options":[{"id":"A","text":"This release has less bugs than the previous one."},{"id":"B","text":"This release has fewer bugs than the previous one."},{"id":"C","text":"This release has lesser bugs than the previous one."},{"id":"D","text":"This release has fewer bug than the previous one."}],"correctId":"B","rationale":"\"Fewer\" is used with countable nouns such as \"bugs,\" while \"less\" is used with uncountable quantities. Since bugs can be counted, \"fewer bugs\" is correct.","reference":"English › Fewer vs. less"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"MEDIUM","prompt":"Choose the sentence that uses the confused words correctly.","options":[{"id":"A","text":"Whose responsible for ensuring the certificate doesn't expire?"},{"id":"B","text":"Who's responsible for ensuring the certificate doesn't expire?"},{"id":"C","text":"Who's responsible for insuring the certificate doesn't expire?"},{"id":"D","text":"Whose responsible for insuring the certificate doesn't expire?"}],"correctId":"B","rationale":"\"Who's\" is the contraction of \"who is,\" which fits the question, while \"whose\" is possessive. \"Ensure\" means to make certain, whereas \"insure\" refers to insurance; the sentence needs \"ensuring.\"","reference":"English › Who's vs. whose; ensure vs. insure"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"MEDIUM","prompt":"Which sentence uses \"principal\" and \"principle\" correctly?","options":[{"id":"A","text":"The principle objective is to uphold the principal of transparency."},{"id":"B","text":"The principal objective is to uphold the principle of transparency."},{"id":"C","text":"The principle objective is to uphold the principle of transparency."},{"id":"D","text":"The principal objective is to uphold the principal of transparency."}],"correctId":"B","rationale":"\"Principal\" as an adjective means main or primary (\"principal objective\"), while \"principle\" is a noun meaning a fundamental rule or belief (\"principle of transparency\"). Option B assigns each word its correct role.","reference":"English › Principal vs. principle"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"MEDIUM","prompt":"Choose the sentence that uses \"complement\" or \"compliment\" correctly.","options":[{"id":"A","text":"The new firewall will compliment our existing defenses."},{"id":"B","text":"The new firewall will complement our existing defenses."},{"id":"C","text":"The new firewall will complament our existing defenses."},{"id":"D","text":"The ambassador complemented the team on their work."}],"correctId":"B","rationale":"\"Complement\" means to complete or enhance something, which fits how the firewall works with existing defenses. \"Compliment\" means to praise, so D misuses it; C is a misspelling.","reference":"English › Complement vs. compliment"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"HARD","prompt":"Choose the best correction for the underlined word: \"The committee will need to insure the building against flood damage before the archives are moved.\"","options":[{"id":"A","text":"ensure"},{"id":"B","text":"insure"},{"id":"C","text":"assure"},{"id":"D","text":"endure"}],"correctId":"B","rationale":"\"Insure\" means to obtain or provide insurance against loss, which is the meaning here (protecting the building against flood damage). \"Ensure\" means to make certain, \"assure\" means to reassure a person, and \"endure\" means to withstand.","reference":"English › Ensure vs. insure vs. assure"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"HARD","prompt":"Which sentence uses all of the confused words correctly?","options":[{"id":"A","text":"Its clear that the agency lost it's certification because their records were incomplete."},{"id":"B","text":"It's clear that the agency lost its certification because their records were incomplete."},{"id":"C","text":"It's clear that the agency lost it's certification because there records were incomplete."},{"id":"D","text":"Its clear that the agency lost its certification because they're records were incomplete."}],"correctId":"B","rationale":"\"It's\" is the contraction \"it is,\" \"its\" is the possessive, and \"their\" is the possessive of \"they.\" Option B uses \"It's\" for \"it is,\" \"its certification\" for possession, and \"their records\" correctly.","reference":"English › Its/it's and their/there/they're"},
{"section":"ENGLISH_EXPRESSION","topic":"Usage & Word Choice","difficulty":"HARD","prompt":"Choose the best correction for the underlined part: \"The protocol change had a positive affect on latency, and it will affect throughput as well.\"","options":[{"id":"A","text":"affect ... affect"},{"id":"B","text":"effect ... effect"},{"id":"C","text":"effect ... affect"},{"id":"D","text":"affect ... effect"}],"correctId":"C","rationale":"The first blank is a noun meaning result, which requires \"effect.\" The second blank is a verb meaning to influence, which requires \"affect.\" Only option C assigns each form correctly.","reference":"English › Affect vs. effect"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"EASY","prompt":"Which sentence has correct parallel structure?","options":[{"id":"A","text":"The new attaché is responsible for drafting cables, scheduling briefings, and to maintain the secure database."},{"id":"B","text":"The new attaché is responsible for drafting cables, scheduling briefings, and maintaining the secure database."},{"id":"C","text":"The new attaché is responsible for drafting cables, to schedule briefings, and maintaining the secure database."},{"id":"D","text":"The new attaché is responsible for the drafting of cables, schedules briefings, and maintaining the secure database."}],"correctId":"B","rationale":"Items in a series should share the same grammatical form. Option B uses three parallel gerunds (drafting, scheduling, maintaining), while the others mix gerunds with infinitives or finite verbs.","reference":"English › Parallelism"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"EASY","prompt":"Which option corrects the sentence fragment: \"Because the network outage lasted several hours and disrupted every embassy in the region.\"?","options":[{"id":"A","text":"Because the network outage lasted several hours and disrupted every embassy in the region."},{"id":"B","text":"Because the network outage lasted several hours and disrupted every embassy in the region, staff postponed all virtual consultations."},{"id":"C","text":"The network outage lasting several hours and disrupting every embassy in the region."},{"id":"D","text":"Because of the network outage lasted several hours, disrupting every embassy in the region."}],"correctId":"B","rationale":"A subordinate clause beginning with \"Because\" cannot stand alone; it needs an independent clause to complete the thought. Option B attaches a main clause, while C is a phrase and D is ungrammatical.","reference":"English › Sentence Fragments"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"EASY","prompt":"Which revision corrects the run-on sentence: \"The server crashed at noon the team restored it by three.\"?","options":[{"id":"A","text":"The server crashed at noon the team restored it by three."},{"id":"B","text":"The server crashed at noon, the team restored it by three."},{"id":"C","text":"The server crashed at noon, but the team restored it by three."},{"id":"D","text":"The server crashed at noon however the team restored it by three."}],"correctId":"C","rationale":"Two independent clauses must be joined by a comma plus a coordinating conjunction, a semicolon, or a period. Option C adds \"but,\" while B is a comma splice and D omits required punctuation around \"however.\"","reference":"English › Run-on Sentences"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"MEDIUM","prompt":"Which revision corrects the dangling modifier: \"After reviewing the encryption logs, the breach was traced to an outdated certificate.\"?","options":[{"id":"A","text":"After reviewing the encryption logs, the breach was traced to an outdated certificate."},{"id":"B","text":"After reviewing the encryption logs, an outdated certificate was traced to the breach."},{"id":"C","text":"After reviewing the encryption logs, the analysts traced the breach to an outdated certificate."},{"id":"D","text":"After the encryption logs were reviewed, the breach was traced to an outdated certificate by an outdated certificate."}],"correctId":"C","rationale":"An introductory participial phrase must modify the subject that immediately follows it; the breach did not review the logs. Option C supplies \"the analysts\" as the logical actor, while B and D leave the modifier dangling or are nonsensical.","reference":"English › Dangling Modifiers"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"MEDIUM","prompt":"Which sentence places the modifier correctly to convey that only the consul, not the report, was authorized?","options":[{"id":"A","text":"The consul released the report that was authorized to the press."},{"id":"B","text":"The consul, who was authorized, released the report to the press."},{"id":"C","text":"Authorized to the press, the consul released the report."},{"id":"D","text":"The consul released the report to the press that was authorized."}],"correctId":"B","rationale":"A modifier should sit next to the word it describes. Option B uses a relative clause adjacent to \"consul\" to show the consul was authorized, whereas A, C, and D misattach the modifier to the report or the press.","reference":"English › Misplaced Modifiers"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"MEDIUM","prompt":"Which sentence corrects the faulty comparison: \"The bandwidth at our mission is greater than the consulate.\"?","options":[{"id":"A","text":"The bandwidth at our mission is greater than the consulate."},{"id":"B","text":"The bandwidth at our mission is greater than the consulate's."},{"id":"C","text":"The bandwidth at our mission is more greater than the consulate."},{"id":"D","text":"The bandwidth at our mission is greater compared to the consulate has."}],"correctId":"B","rationale":"A comparison must pair like with like; the original illogically compares bandwidth to a building. Option B compares bandwidth to \"the consulate's\" (bandwidth) using the possessive, while C is a double comparative and D is ungrammatical.","reference":"English › Faulty Comparisons"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"MEDIUM","prompt":"Which sentence uses subordination most effectively to show the logical relationship between the ideas?","options":[{"id":"A","text":"The firewall flagged the file, and the file was quarantined, and the analyst was notified."},{"id":"B","text":"Because the firewall flagged the file, it was quarantined and the analyst was notified."},{"id":"C","text":"The firewall flagged the file, the file was quarantined, the analyst was notified."},{"id":"D","text":"The firewall flagged the file, so the file, which was quarantined, and the analyst was notified."}],"correctId":"B","rationale":"Subordination uses a dependent clause to signal cause and effect, producing tighter, clearer prose. Option B subordinates the trigger with \"Because,\" while A merely strings clauses with \"and,\" C is a comma splice, and D is garbled.","reference":"English › Coordination & Subordination"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"MEDIUM","prompt":"Which sentence has correct parallel structure?","options":[{"id":"A","text":"The protocol requires officers not only to encrypt their drives but also reporting losses immediately."},{"id":"B","text":"The protocol requires officers not only to encrypt their drives but also to report losses immediately."},{"id":"C","text":"The protocol requires officers not only encrypting their drives but also to report losses immediately."},{"id":"D","text":"The protocol requires officers not only to encrypt their drives but reporting losses immediately also."}],"correctId":"B","rationale":"Correlative conjunctions such as \"not only ... but also\" must connect grammatically parallel elements. Option B pairs two infinitives (to encrypt, to report), while the other options mix infinitives with gerunds or misorder the construction.","reference":"English › Parallelism"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"HARD","prompt":"Which sentence corrects both the comma splice and the faulty parallelism in: \"The delegation valued transparency, accountability, and being efficient, they praised the new audit system.\"?","options":[{"id":"A","text":"The delegation valued transparency, accountability, and being efficient, they praised the new audit system."},{"id":"B","text":"The delegation valued transparency, accountability, and efficiency; they praised the new audit system."},{"id":"C","text":"The delegation valued transparency, accountability, and efficiency, they praised the new audit system."},{"id":"D","text":"The delegation valued transparency, accountability, and being efficient; they praised the new audit system."}],"correctId":"B","rationale":"The list needs three parallel nouns and the two independent clauses need proper separation. Option B uses the noun \"efficiency\" for parallelism and a semicolon to join the clauses, while C and D fix only one error and A fixes neither.","reference":"English › Parallelism"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"HARD","prompt":"Which revision corrects the dangling modifier while preserving the intended meaning: \"To qualify for the secure clearance, a full background check must be completed by the applicant.\"?","options":[{"id":"A","text":"To qualify for the secure clearance, a full background check must be completed by the applicant."},{"id":"B","text":"To qualify for the secure clearance, the applicant must complete a full background check."},{"id":"C","text":"To qualify for the secure clearance, completing a full background check is required."},{"id":"D","text":"A full background check, to qualify for the secure clearance, must be completed."}],"correctId":"B","rationale":"The infinitive phrase \"To qualify\" must modify the person who qualifies, not the background check. Option B makes \"the applicant\" the subject performing the action, while the other versions leave the modifier attached to an inanimate or absent actor.","reference":"English › Dangling Modifiers"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"HARD","prompt":"Which sentence is grammatically complete and free of fragments and run-ons?","options":[{"id":"A","text":"Although the migration finished ahead of schedule, which surprised the steering committee that had braced for delays."},{"id":"B","text":"The migration finished ahead of schedule, which surprised the steering committee, the committee had braced for delays."},{"id":"C","text":"The migration finished ahead of schedule, surprising the steering committee, which had braced for delays."},{"id":"D","text":"The migration finished ahead of schedule it surprised the steering committee that had braced for delays."}],"correctId":"C","rationale":"A complete sentence needs an independent clause without splices or fused clauses. Option C uses a participial phrase and a relative clause correctly; A is a fragment, B is a comma splice, and D is a run-on.","reference":"English › Sentence Fragments"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"HARD","prompt":"Which sentence corrects the faulty comparison: \"Unlike most legacy systems, the new platform's response time is faster and easier to monitor.\"?","options":[{"id":"A","text":"Unlike most legacy systems, the new platform's response time is faster and easier to monitor."},{"id":"B","text":"Unlike most legacy systems, the new platform responds faster and is easier to monitor."},{"id":"C","text":"Unlike most legacy systems, the new platform's response time responds faster and is easier to monitor."},{"id":"D","text":"Unlike most legacy systems, faster response time and easier monitoring describe the new platform."}],"correctId":"B","rationale":"The introductory phrase compares \"legacy systems\" with what follows, but the original pairs systems with a \"response time,\" an illogical match. Option B makes \"the new platform\" the subject so the comparison is system-to-system, while the others keep the mismatch or are awkward.","reference":"English › Faulty Comparisons"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"MEDIUM","prompt":"Which revision best fixes the misplaced modifier: \"The minister discussed the cyberattack on the news that crippled the ministry.\"?","options":[{"id":"A","text":"The minister discussed the cyberattack on the news that crippled the ministry."},{"id":"B","text":"On the news, the minister discussed the cyberattack that crippled the ministry."},{"id":"C","text":"The minister discussed on the news the cyberattack crippling that the ministry."},{"id":"D","text":"The minister, on the news that crippled the ministry, discussed the cyberattack."}],"correctId":"B","rationale":"The clause \"that crippled the ministry\" should describe the cyberattack, not the news. Option B moves \"On the news\" to the front so the relative clause sits beside \"cyberattack,\" while the others leave the modifier misplaced or are ungrammatical.","reference":"English › Misplaced Modifiers"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"EASY","prompt":"Which sentence avoids a comma splice?","options":[{"id":"A","text":"The patch was tested overnight, it deploys at dawn."},{"id":"B","text":"The patch was tested overnight; it deploys at dawn."},{"id":"C","text":"The patch was tested overnight it deploys at dawn."},{"id":"D","text":"The patch was tested overnight, deploys at dawn it does."}],"correctId":"B","rationale":"Two independent clauses cannot be joined by a comma alone. Option B uses a semicolon to link the closely related clauses, while A is a comma splice, C is a fused sentence, and D is ungrammatical.","reference":"English › Run-on Sentences"},
{"section":"ENGLISH_EXPRESSION","topic":"Syntax & Sentence Structure","difficulty":"HARD","prompt":"Which sentence maintains parallel structure across all of its compound elements?","options":[{"id":"A","text":"The audit found that passwords were weak, that access logs were incomplete, and a lack of two-factor authentication."},{"id":"B","text":"The audit found that passwords were weak, that access logs were incomplete, and that two-factor authentication was absent."},{"id":"C","text":"The audit found that passwords were weak, access logs being incomplete, and two-factor authentication absent."},{"id":"D","text":"The audit found weak passwords, that access logs were incomplete, and that two-factor authentication was absent."}],"correctId":"B","rationale":"When a series follows \"found that,\" each item should be a parallel \"that\" clause. Option B repeats the structure consistently, while A, C, and D mix noun phrases or participles with the clauses.","reference":"English › Parallelism"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"EASY","prompt":"Which sentence is the most concise and professional?","options":[{"id":"A","text":"In light of the fact that the deadline has now passed, we are going to need to ask for an extension at this point in time."},{"id":"B","text":"Because the deadline has passed, we request an extension."},{"id":"C","text":"Due to the fact that the deadline is something that has already passed, an extension is what we would like to request."},{"id":"D","text":"The deadline having passed, it is the case that we are requesting, if possible, an extension."}],"correctId":"B","rationale":"Concise professional writing removes filler such as \"in light of the fact that\" and \"at this point in time.\" Option B states the cause and the request in eight words, while the others pad the sentence with redundant phrases.","reference":"English › Concision"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"EASY","prompt":"Which sentence uses the active voice for a clearer, more direct statement?","options":[{"id":"A","text":"The vulnerability was identified by the security team during the routine scan."},{"id":"B","text":"The security team identified the vulnerability during the routine scan."},{"id":"C","text":"It was during the routine scan that the vulnerability came to be identified."},{"id":"D","text":"During the routine scan, the vulnerability was being identified by the security team."}],"correctId":"B","rationale":"Active voice places the actor before the verb, making the sentence more direct and concise. Option B leads with \"The security team\" as the subject, while the others bury the actor in a passive or wordy construction.","reference":"English › Active vs Passive Voice"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"EASY","prompt":"Which closing is most appropriate for a formal letter to a foreign ministry official?","options":[{"id":"A","text":"Thanks a million, talk soon!"},{"id":"B","text":"Respectfully yours,"},{"id":"C","text":"Catch you later,"},{"id":"D","text":"Cheers,"}],"correctId":"B","rationale":"Formal official correspondence calls for a dignified, conventional closing. \"Respectfully yours\" matches the register of a diplomatic letter, while the other options are casual and inappropriate for the context.","reference":"English › Salutations & Closings"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"EASY","prompt":"Which salutation is most appropriate when writing to a recipient whose name you do not know at a partner agency?","options":[{"id":"A","text":"Hey there,"},{"id":"B","text":"To whom it may concern,"},{"id":"C","text":"Yo team,"},{"id":"D","text":"Dear Sir or Madam,"}],"correctId":"D","rationale":"When the specific recipient is unknown but the letter is addressed to a person at an organization, \"Dear Sir or Madam\" is the standard formal salutation. \"To whom it may concern\" suits general notices rather than directed correspondence, and the other options are too casual.","reference":"English › Salutations & Closings"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which is the clearest, most direct version of: \"It is the recommendation of this office that consideration be given to the postponement of the system upgrade.\"?","options":[{"id":"A","text":"It is the recommendation of this office that consideration be given to the postponement of the system upgrade."},{"id":"B","text":"This office recommends postponing the system upgrade."},{"id":"C","text":"Consideration regarding a possible postponement of the upgrade is being recommended by this office."},{"id":"D","text":"It is recommended that the postponement of the system upgrade be given due consideration by all."}],"correctId":"B","rationale":"Direct writing names the actor and the action and drops nominalizations like \"recommendation\" and \"postponement.\" Option B says who recommends what in five words, while the others rely on passive, noun-heavy phrasing.","reference":"English › Clarity"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which sentence sets the most appropriate professional tone for declining a vendor's proposal?","options":[{"id":"A","text":"Your proposal was a total miss, so we're passing."},{"id":"B","text":"After careful review, we have decided not to proceed with your proposal at this time."},{"id":"C","text":"We don't want what you're selling, sorry."},{"id":"D","text":"Regrettably, it must be conveyed that the proposal in question shall not be advanced forward henceforth."}],"correctId":"B","rationale":"A professional decline should be courteous, clear, and measured. Option B acknowledges the review and states the decision politely, while A and C are too blunt or casual, and D is stilted and overblown.","reference":"English › Tone & Formality"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which sentence eliminates wordiness most effectively?","options":[{"id":"A","text":"At this present moment in time, we are currently in the process of conducting an evaluation of the firewall."},{"id":"B","text":"We are evaluating the firewall."},{"id":"C","text":"We are now, at present, undertaking the process of firewall evaluation activities."},{"id":"D","text":"An evaluation of the firewall is something that is currently being undertaken by us."}],"correctId":"B","rationale":"Redundant time markers and \"in the process of conducting an evaluation\" can collapse to a single verb. Option B says the same thing in four words, while the others repeat \"present/currently/now\" and use empty noun phrases.","reference":"English › Concision"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which is the best topic sentence for a paragraph that then describes specific causes of the data center failure, the response timeline, and the corrective steps taken?","options":[{"id":"A","text":"Data centers are complicated facilities that many organizations rely on every day."},{"id":"B","text":"This report examines the causes of the data center failure, the timeline of our response, and the corrective measures now in place."},{"id":"C","text":"The data center is located in the east wing and was built in 2014."},{"id":"D","text":"Failures can happen, and when they do, it is important to think carefully about many things."}],"correctId":"B","rationale":"A strong topic sentence previews the paragraph's specific contents and scope. Option B names the three subtopics the paragraph will cover, while A and D are vague generalities and C introduces an irrelevant detail.","reference":"English › Topic Sentences"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which sentence appropriately uses passive voice rather than active voice?","options":[{"id":"A","text":"Someone misconfigured the router on Tuesday, and the router was misconfigured by someone."},{"id":"B","text":"The classified files were accessed without authorization, and an investigation is under way."},{"id":"C","text":"We accessed the classified files without authorization."},{"id":"D","text":"An investigation, by us, of the files being accessed is what is happening now."}],"correctId":"B","rationale":"Passive voice is appropriate when the actor is unknown or the action itself is the focus, as in incident reporting. Option B keeps attention on the breach without naming an unknown perpetrator, while C wrongly implies the writer is the offender and A and D are redundant or garbled.","reference":"English › Active vs Passive Voice"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"HARD","prompt":"Which is the most effective revision of: \"Pursuant to your earlier communication, it should be noted that the requested credentials have, as of now, not yet been received by our department.\"?","options":[{"id":"A","text":"Pursuant to your earlier communication, it should be noted that the requested credentials have, as of now, not yet been received by our department."},{"id":"B","text":"We have not yet received the credentials you requested."},{"id":"C","text":"As per your prior message, please be advised that receipt of the said credentials has not yet occurred on our end."},{"id":"D","text":"It is to be noted that the credentials, which were requested, remain in a state of non-receipt at this department."}],"correctId":"B","rationale":"The most effective revision is concise, active, and clear while preserving the meaning. Option B states the actor, the verb, and the object plainly, whereas A, C, and D retain bureaucratic filler and passive constructions.","reference":"English › Most Effective Revision"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"HARD","prompt":"Which sentence best balances diplomatic tact with clarity when reporting a missed commitment to a senior counterpart?","options":[{"id":"A","text":"You failed to deliver the integration on time, which caused us serious problems."},{"id":"B","text":"We note that the integration milestone was not met as scheduled, and we would welcome a revised timeline at your earliest convenience."},{"id":"C","text":"The integration thing didn't happen when it was supposed to, FYI."},{"id":"D","text":"It is with the deepest possible regret and profound disappointment that we are compelled to observe the catastrophic nonfulfillment of the integration milestone."}],"correctId":"B","rationale":"Diplomatic correspondence should name the issue clearly while remaining courteous and forward-looking. Option B states the missed milestone and requests a remedy without blame, whereas A is accusatory, C is too casual, and D is melodramatic and overstated.","reference":"English › Tone & Formality"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"HARD","prompt":"Which revision conveys the same information with the greatest concision and clarity: \"There are several different members of the technical staff who are of the opinion that the proposed schedule is one that may not be entirely realistic.\"?","options":[{"id":"A","text":"There are several different members of the technical staff who are of the opinion that the proposed schedule is one that may not be entirely realistic."},{"id":"B","text":"Several technical staff members believe the proposed schedule is unrealistic."},{"id":"C","text":"It is the case that several staff members hold the opinion that the schedule, as proposed, might possibly be unrealistic to some degree."},{"id":"D","text":"The opinion is held by several members of the technical staff that the proposed schedule may not be realistic in its entirety."}],"correctId":"B","rationale":"Concision removes \"there are,\" \"who are of the opinion that,\" and \"one that.\" Option B replaces them with a direct subject-verb-object structure, while C and D retain expletive constructions, passivity, and hedging.","reference":"English › Concision"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"HARD","prompt":"Which sentence is the clearest and most professional rewrite of: \"Owing to circumstances beyond our control of a technical nature, the rollout, unfortunately, will have to be subject to a delay.\"?","options":[{"id":"A","text":"Owing to circumstances beyond our control of a technical nature, the rollout, unfortunately, will have to be subject to a delay."},{"id":"B","text":"A technical issue will delay the rollout."},{"id":"C","text":"Unfortunately, due to certain technical circumstances that are beyond our control, a delay of the rollout will be necessitated."},{"id":"D","text":"The rollout, owing to technical matters, is something that will, regrettably, end up being delayed."}],"correctId":"B","rationale":"The clearest version names the cause and the effect directly and drops vague hedging like \"circumstances beyond our control of a technical nature.\" Option B uses an active subject and verb, while A, C, and D remain wordy and indirect.","reference":"English › Clarity"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which sentence maintains an appropriately formal register for an official memorandum?","options":[{"id":"A","text":"Heads up: the access policy is getting a big overhaul next week."},{"id":"B","text":"Please be advised that the access policy will be revised effective next week."},{"id":"C","text":"Just so you know, we're totally redoing the access policy soon."},{"id":"D","text":"The access policy? Yeah, it's changing, big time, pretty soon."}],"correctId":"B","rationale":"An official memorandum requires neutral, formal phrasing. Option B states the change and its effective date in a measured tone, while the other options use slang, contractions, or conversational fragments unsuited to the genre.","reference":"English › Tone & Formality"},
{"section":"ENGLISH_EXPRESSION","topic":"Professional Communication","difficulty":"MEDIUM","prompt":"Which is the best topic sentence for a paragraph arguing that the agency should adopt multifactor authentication?","options":[{"id":"A","text":"Passwords have existed for a very long time in computing history."},{"id":"B","text":"The agency should adopt multifactor authentication to reduce the risk of unauthorized access to sensitive systems."},{"id":"C","text":"There are many security measures, and some are better than others in various ways."},{"id":"D","text":"Multifactor authentication is a phrase that appears frequently in industry literature."}],"correctId":"B","rationale":"A topic sentence for an argument should state a clear, debatable claim that the paragraph will support. Option B asserts the recommendation and its rationale, while A, C, and D are background filler or vague observations.","reference":"English › Topic Sentences"}
] as const;
